1	package cmd
2	
3	import (
4		"encoding/json"
5		"sort"
6		"strings"
7	
8		"forge-cli/pkg/forgeconfig"
9		"forge-cli/pkg/types"
10	
11		"github.com/spf13/cobra"
12	)
13	
14	// KnownSurfaceTypes re-exports the canonical set from forgeconfig.
15	// Unknown types are filtered from --types output and silently ignored in listings.
16	var KnownSurfaceTypes = forgeconfig.KnownSurfaceTypes
17	
18	var surfacesTypesFlag bool
19	var surfacesJSONFlag bool
20	
21	var surfacesCmd = &cobra.Command{
22		Use:   "surfaces [path]",
23		Short: "Query project surfaces configuration",
24		Long: `Query the surfaces field from .forge/config.yaml.
25	
26	Without arguments: scalar form outputs the single type; map form outputs
27	one "path=surface" line per entry. Exit 0 always.
28	
29	With a path argument: returns the surface type for that path using
30	segment prefix matching. Exit 0 on match, exit 1 with stderr error on
31	no match.
32	
33	With --types: outputs space-separated deduplicated list of known surface types.
34	
35	With --json: outputs structured JSON. List mode: {"surfaces": [...]};
36	query mode: [{"key": ..., "type": ...}]; types mode: {"types": [...]}.`,
37		Args:          cobra.MaximumNArgs(1),
38		SilenceErrors: true,
39		SilenceUsage:  true,
40		RunE:          runSurfaces,
41	}
42	
43	func init() {
44		surfacesCmd.Flags().BoolVar(&surfacesTypesFlag, "types", false, "list deduplicated surface types")
45		surfacesCmd.Flags().BoolVar(&surfacesJSONFlag, "json", false, "output in JSON format")
46		surfacesCmd.Flags().String("project-root", "", "project root directory (defaults to auto-detection)")
47	}
48	
49	// jsonError writes a structured JSON error to stderr when --json is active.
50	// Hard Rule: must use json.NewEncoder(cmd.ErrOrStderr()).Encode(), not fmt.Fprintf.
51	func jsonError(cmd *cobra.Command, message string) error {
52		return json.NewEncoder(cmd.ErrOrStderr()).Encode(map[string]string{"error": message})
53	}
54	
55	// runSurfaces implements the three sub-invocations of the surfaces command.
56	func runSurfaces(cmd *cobra.Command, args []string) error {
57		projectRoot := resolveProjectRoot(cmd)
58	
59		surfaces, err := forgeconfig.ReadSurfaces(projectRoot)
60		if err != nil {
61			if surfacesJSONFlag {
62				_ = jsonError(cmd, err.Error())
63				return err
64			}
65			return err
66		}
67	
68		// --types: output deduplicated known types
69		if surfacesTypesFlag {
70			return runSurfacesTypes(cmd, surfaces)
71		}
72	
73		// No args: list all surfaces
74		if len(args) == 0 {
75			return runSurfacesList(cmd, surfaces)
76		}
77	
78		// Path query: match surface for given path
79		return runSurfacesQuery(cmd, surfaces, args[0])
80	}
81	
82	// runSurfacesList outputs all surfaces.
83	// Scalar form: single type string.
84	// Map form: one "path=surface" line per entry.
85	func runSurfacesList(cmd *cobra.Command, surfaces map[string]string) error {
86		if len(surfaces) == 0 {
87			if surfacesJSONFlag {
88				// No surfaces configured -- output JSON error to stderr
89				_ = jsonError(cmd, "no surface configured; run `forge init` to configure surfaces")
90				return &surfacesPathError{message: "no surface configured"}
91			}
92			return nil
93		}
94	
95		// JSON mode: output {"surfaces": [...]}
96		if surfacesJSONFlag {
97			return runSurfacesListJSON(cmd, surfaces)
98		}
99	
100		out := cmd.OutOrStdout()
101	
102		// Scalar form: single "." key
103		if len(surfaces) == 1 {
104			if v, ok := surfaces["."]; ok {
105				write(out, "%s\n", v)
106				return nil
107			}
108		}
109	
110		// Map form: output sorted path=surface lines
111		paths := make([]string, 0, len(surfaces))
112		for p := range surfaces {
113			paths = append(paths, p)
114		}
115		sort.Strings(paths)
116	
117		for _, p := range paths {
118			write(out, "%s=%s\n", p, surfaces[p])
119		}
120		return nil
121	}
122	
123	// runSurfacesListJSON outputs all surfaces as JSON.
124	func runSurfacesListJSON(cmd *cobra.Command, surfaces map[string]string) error {
125		type jsonEntry struct {
126			Key  string `json:"key"`
127			Type string `json:"type"`
128		}
129	
130		entries := make([]jsonEntry, 0, len(surfaces))
131		for k, v := range surfaces {
132			entries = append(entries, jsonEntry{Key: k, Type: v})
133		}
134		// Sort by key for deterministic output
135		sort.Slice(entries, func(i, j int) bool {
136			return entries[i].Key < entries[j].Key
137		})
138	
139		return json.NewEncoder(cmd.OutOrStdout()).Encode(map[string][]jsonEntry{
140			"surfaces": entries,
141		})
142	}
143	
144	// surfacesPathError is a sentinel error type for unmatched path queries.
145	// The actual error message is written directly to stderr before returning
146	// this error, ensuring raw unformatted output on stderr (no "Error: " prefix).
147	type surfacesPathError struct {
148		message string
149	}
150	
151	func (e *surfacesPathError) Error() string { return e.message }
152	
153	// runSurfacesQuery finds the surface type for a query path.
154	// Exit 0 on match (stdout), exit 1 on no match (stderr).
155	// Error message is written raw to stderr -- no formatting prefix.
156	func runSurfacesQuery(cmd *cobra.Command, surfaces map[string]string, query string) error {
157		// Handle empty surfaces before calling MatchSurface for JSON mode distinction
158		if len(surfaces) == 0 {
159			if surfacesJSONFlag {
160				_ = jsonError(cmd, "no surface configured; run `forge init` to configure surfaces")
161				return &surfacesPathError{message: "no surface configured"}
162			}
163			write(cmd.ErrOrStderr(), "no surface configured; run `forge init` to configure surfaces\n")
164			return &surfacesPathError{message: "no surface configured"}
165		}
166	
167		match, err := forgeconfig.MatchSurface(surfaces, query)
168		if err != nil {
169			if surfacesJSONFlag {
170				// Path-specific no-match: output empty array, exit 0
171				return json.NewEncoder(cmd.OutOrStdout()).Encode([]forgeconfig.SurfaceMatch{})
172			}
173			// Write raw error to stderr (no "Error: " prefix per Hard Rules)
174			write(cmd.ErrOrStderr(), "%s\n", err.Error())
175			return &surfacesPathError{message: err.Error()}
176		}
177	
178		if surfacesJSONFlag {
179			return json.NewEncoder(cmd.OutOrStdout()).Encode([]forgeconfig.SurfaceMatch{match})
180		}
181	
182		write(cmd.OutOrStdout(), "%s\n", match.Type)
183		return nil
184	}
185	
186	// runSurfacesTypes outputs deduplicated known surface types.
187	func runSurfacesTypes(cmd *cobra.Command, surfaces map[string]string) error {
188		if len(surfaces) == 0 {
189			if surfacesJSONFlag {
190				_ = jsonError(cmd, "no surface configured; run `forge init` to configure surfaces")
191				return &surfacesPathError{message: "no surface configured"}
192			}
193			return nil
194		}
195	
196		seen := make(map[string]bool)
197		var surfaceTypes []string
198		for _, typ := range surfaces {
199			if seen[typ] {
200				continue
201			}
202			if !KnownSurfaceTypes[types.SurfaceType(typ)] {
203				continue
204			}
205			seen[typ] = true
206			surfaceTypes = append(surfaceTypes, typ)
207		}
208	
209		if len(surfaceTypes) == 0 {
210			if surfacesJSONFlag {
211				return json.NewEncoder(cmd.OutOrStdout()).Encode(map[string][]string{"types": {}})
212			}
213			return nil
214		}
215	
216		sort.Strings(surfaceTypes)
217	
218		if surfacesJSONFlag {
219			return json.NewEncoder(cmd.OutOrStdout()).Encode(map[string][]string{"types": surfaceTypes})
220		}
221	
222		write(cmd.OutOrStdout(), "%s\n", strings.Join(surfaceTypes, " "))
223		return nil
224	}
