1	package cmd
2	
3	import (
4		"errors"
5		"fmt"
6		"io"
7		"os"
8		"path/filepath"
9		"strings"
10	
11		"forge-cli/pkg/feature"
12		"forge-cli/pkg/forgeconfig"
13		"forge-cli/pkg/just"
14	
15		"github.com/charmbracelet/huh"
16		"github.com/charmbracelet/lipgloss"
17		"github.com/spf13/cobra"
18	)
19	
20	var initCmd = &cobra.Command{
21		Use:   "init",
22		Short: "Initialize forge project environment",
23		Long: `One-stop initialization for forge project.
24	
25	Creates .forge/ directory, appends runtime entries to .gitignore,
26	ensures just is installed, and runs interactive config if
27	.forge/config.yaml doesn't exist.`,
28		Args: cobra.NoArgs,
29		RunE: runInit,
30	}
31	
32	func init() {
33		initCmd.Flags().String("project-root", "", "project root directory (defaults to current directory)")
34		initCmd.Flags().Bool("skip-just", false, "skip just installation check")
35	}
36	
37	// gitignoreEntries are the lines to append to .gitignore.
38	var gitignoreEntries = []string{
39		"# Forge",
40		".forge/state.json",
41		".forge/test-state.json",
42		".forge/worktrees/",
43		"docs/features/*/tasks/process/",
44		"docs/features/*/tasks/index.json.lock",
45		"docs/features/*/testing/results/",
46		feature.TestResultsDir + "/",
47	}
48	
49	// initAction records a single action taken during init.
50	type initAction struct {
51		status string // CREATED, APPENDED, INSTALLED, SKIPPED, FAILED, CANCELLED
52		target string // file or directory path
53		detail string // extra info (e.g., "5 entries", "from template")
54	}
55	
56	func runInit(cmd *cobra.Command, _ []string) error {
57		projectRoot, _ := cmd.Flags().GetString("project-root")
58		if projectRoot == "" {
59			projectRoot = "."
60		}
61	
62		skipJust, _ := cmd.Flags().GetBool("skip-just")
63	
64		out := cmd.OutOrStdout()
65		var actions []initAction
66	
67		// Step 1: Create .forge/ directory
68		action := createForgeDir(projectRoot)
69		actions = append(actions, action)
70	
71		// Step 2: Update .gitignore
72		action = updateGitignore(projectRoot)
73		actions = append(actions, action)
74	
75		// Step 4: Ensure just is installed
76		action = ensureJustStep(skipJust, cmd.InOrStdin(), out)
77		actions = append(actions, action)
78	
79		// Step 5: Interactive config (only if config doesn't exist)
80		action = configInitFunc(projectRoot)
81		actions = append(actions, action)
82	
83		// Step 6: Surface detection and TUI confirmation
84		action = surfaceConfigFunc(projectRoot)
85		actions = append(actions, action)
86	
87		// Print summary report
88		printInitSummary(out, actions)
89	
90		return nil
91	}
92	
93	func createForgeDir(projectRoot string) initAction {
94		forgeDir := filepath.Join(projectRoot, feature.ForgeDir)
95		if _, err := os.Stat(forgeDir); err == nil {
96			return initAction{status: "SKIPPED", target: feature.ForgeDir, detail: "already exists"}
97		}
98		if err := os.MkdirAll(forgeDir, 0o755); err != nil {
99			fmt.Fprintf(os.Stderr, "ERROR: failed to create %s: %v\n", forgeDir, err)
100			return initAction{status: "FAILED", target: feature.ForgeDir, detail: err.Error()}
101		}
102		return initAction{status: "CREATED", target: feature.ForgeDir}
103	}
104	
105	func updateGitignore(projectRoot string) initAction {
106		gitignorePath := filepath.Join(projectRoot, ".gitignore")
107	
108		var existingContent string
109		data, err := os.ReadFile(gitignorePath)
110		if err == nil {
111			existingContent = string(data)
112		}
113	
114		toAppend := buildGitignoreAppend(existingContent, gitignoreEntries)
115		if len(toAppend) == 0 {
116			return initAction{status: "SKIPPED", target: ".gitignore", detail: "all entries already present"}
117		}
118	
119		var buf strings.Builder
120		if existingContent != "" && !strings.HasSuffix(existingContent, "\n") {
121			buf.WriteByte('\n')
122		}
123		for _, line := range toAppend {
124			buf.WriteString(line)
125			buf.WriteByte('\n')
126		}
127	
128		f, err := os.OpenFile(gitignorePath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
129		if err != nil {
130			fmt.Fprintf(os.Stderr, "ERROR: failed to update .gitignore: %v\n", err)
131			return initAction{status: "FAILED", target: ".gitignore", detail: err.Error()}
132		}
133		defer func() { _ = f.Close() }()
134	
135		if _, err := f.WriteString(buf.String()); err != nil {
136			fmt.Fprintf(os.Stderr, "ERROR: failed to write .gitignore: %v\n", err)
137			return initAction{status: "FAILED", target: ".gitignore", detail: err.Error()}
138		}
139	
140		return initAction{status: "APPENDED", target: ".gitignore", detail: fmt.Sprintf("%d entries", len(toAppend))}
141	}
142	
143	// buildGitignoreAppend returns only the lines that are not already present.
144	func buildGitignoreAppend(existing string, entries []string) []string {
145		existingLines := make(map[string]bool)
146		for _, line := range strings.Split(existing, "\n") {
147			trimmed := strings.TrimSpace(line)
148			if trimmed != "" {
149				existingLines[trimmed] = true
150			}
151		}
152	
153		var toAppend []string
154		for _, entry := range entries {
155			if !existingLines[strings.TrimSpace(entry)] {
156				toAppend = append(toAppend, entry)
157			}
158		}
159		return toAppend
160	}
161	
162	func runConfigInitIfNeeded(projectRoot string) initAction {
163		configFile := filepath.Join(projectRoot, feature.ForgeDir, feature.ForgeConfigFileName)
164	
165		fi, _ := os.Stdin.Stat()
166		if fi.Mode()&os.ModeCharDevice == 0 {
167			return initAction{status: "SKIPPED", target: ".forge/config.yaml", detail: "non-interactive terminal"}
168		}
169	
170		// When config exists, ask if user wants to reconfigure
171		if _, err := os.Stat(configFile); err == nil {
172			reconfigure := false
173			if err := huh.NewForm(huh.NewGroup(
174				huh.NewConfirm().
175					Title("Config already exists. Reconfigure?").
176					Description("Select Yes to overwrite .forge/config.yaml with new settings.").
177					Affirmative("Yes").
178					Negative("No").
179					Value(&reconfigure),
180			)).Run(); err != nil {
181				if errors.Is(err, huh.ErrUserAborted) {
182					return initAction{status: "CANCELLED", target: ".forge/config.yaml", detail: "Ctrl+C"}
183				}
184				return initAction{status: "FAILED", target: ".forge/config.yaml", detail: err.Error()}
185			}
186			if !reconfigure {
187				return initAction{status: "SKIPPED", target: ".forge/config.yaml", detail: "kept existing"}
188			}
189		}
190	
191		// Auto-behavior config
192		auto, cancelled := askAutoBehavior()
193		if cancelled {
194			return initAction{status: "CANCELLED", target: ".forge/config.yaml", detail: "Ctrl+C"}
195		}
196	
197		// Worktree config (optional)
198		worktree, cancelled := askWorktreeConfig()
199		if cancelled {
200			return initAction{status: "CANCELLED", target: ".forge/config.yaml", detail: "Ctrl+C"}
201		}
202	
203		cfg := forgeconfig.Config{
204			Auto:     auto,
205			Worktree: worktree,
206		}
207	
208		if err := writeConfigFile(configFile, &cfg); err != nil {
209			fmt.Fprintf(os.Stderr, "ERROR: failed to write config: %v\n", err)
210			return initAction{status: "FAILED", target: ".forge/config.yaml", detail: err.Error()}
211		}
212	
213		return initAction{status: "CREATED", target: ".forge/config.yaml", detail: "interactive"}
214	}
