216	// modeHighlight styles mode keywords for terminal display.
217	var modeHighlight = lipgloss.NewStyle().Bold(true).Foreground(lipgloss.Color(colorModeHighlight))
218	
219	// hl returns a highlighted version of text using modeHighlight.
220	func hl(text string) string {
221		return modeHighlight.Render(text)
222	}
223	
224	// hlMode returns "Quick mode" or "Full mode" with the whole phrase highlighted.
225	func hlMode(mode string) string {
226		return hl(mode + " mode")
