346	
347	// askAutoBehavior runs the auto-behavior config steps, one question per screen.
348	// Returns the config and whether the user cancelled.
349	func askAutoBehavior() (*forgeconfig.AutoConfig, bool) {
350		defaults := forgeconfig.AutoConfigDefaults()
351		auto := &forgeconfig.AutoConfig{}
352	
353		for _, p := range autoBehaviorPrompts(defaults) {
354			val, ok := askConfirm(p.title, p.desc, p.def)
355			if !ok {
356				return nil, true
357			}
358			p.set(auto, val)
359		}
360	
361		return auto, false
362	}
363	
364	// askWorktreeConfig runs the optional worktree config steps.
365	// Returns nil if both source-branch and copy-files are empty (skippable).
366	// Returns (config, cancelled).
367	func askWorktreeConfig() (*forgeconfig.WorktreeConfig, bool) {
368		var sourceBranch string
369		err := huh.NewForm(huh.NewGroup(
370			huh.NewInput().
371				Title("Worktree source branch (leave empty to skip)").
372				Description("Branch to use as the base for new worktrees (e.g. main, develop).").
373				Value(&sourceBranch),
374		)).Run()
375		if err != nil {
376			if errors.Is(err, huh.ErrUserAborted) {
377				return nil, true
378			}
379			return nil, true
380		}
381	
382		var copyFiles []string
383		// Only ask about copy-files if user provided a source branch
384		if sourceBranch != "" {
385			err = huh.NewForm(huh.NewGroup(
386				huh.NewMultiSelect[string]().
387					Title("Files to copy into worktrees").
388					Description("Select files that should be copied from the source branch when creating a worktree.").
389					Options(
390						huh.NewOption(".env", ".env"),
391						huh.NewOption(".env.local", ".env.local"),
392						huh.NewOption(".env.development", ".env.development"),
393					).
394					Value(&copyFiles),
