489	// runSurfaceConfig runs surface detection and TUI confirmation.
490	// Skipped in non-interactive mode or when config doesn't exist.
491	// Re-run behavior: when config.yaml already has surfaces configured, prompts
492	// the user with Confirm / Re-detect / Edit options.
493	func runSurfaceConfig(projectRoot string) initAction {
494		configFile := filepath.Join(projectRoot, feature.ForgeDir, feature.ForgeConfigFileName)
495	
496		// Only run surface config if config file exists (created by step 5)
497		if _, err := os.Stat(configFile); err != nil {
498			return initAction{status: "SKIPPED", target: "surfaces", detail: "no config file"}
499		}
500	
501		// Check for interactive terminal
502		fi, _ := os.Stdin.Stat()
503		if fi.Mode()&os.ModeCharDevice == 0 {
504			return initAction{status: "SKIPPED", target: "surfaces", detail: "non-interactive terminal"}
505		}
506	
507		// Check if surfaces are already configured (re-run behavior)
508		existingCfg, err := forgeconfig.ReadConfig(projectRoot)
509		if err != nil {
510			return initAction{status: "FAILED", target: "surfaces", detail: err.Error()}
511		}
512	
513		if existingCfg != nil && len(existingCfg.Surfaces) > 0 {
514			// Re-run flow: ask user what to do
515			return handleRerunSurfaceConfig(projectRoot, configFile, existingCfg)
516		}
517	
518		// First-run flow: run detection + TUI confirmation
519		return runNewSurfaceDetection(projectRoot, configFile)
520	}
