522	// handleRerunSurfaceConfig handles the re-run flow when surfaces already exist in config.
523	func handleRerunSurfaceConfig(projectRoot, configFile string, existingCfg *forgeconfig.Config) initAction {
524		action, cancelled := askRerunPrompt(existingCfg.Surfaces)
525		if cancelled {
526			return initAction{status: "CANCELLED", target: "surfaces", detail: "Ctrl+C"}
527		}
528	
529		switch action {
530		case "confirm":
531			// Keep existing surfaces
532			return initAction{status: "SKIPPED", target: "surfaces", detail: "already configured"}
533		case "edit":
534			// Hard Rule: Edit calls the same manualSurfaceEntry function as first-run
535			surfaces, cancelled := manualSurfaceEntry()
536			if cancelled {
537				return initAction{status: "CANCELLED", target: "surfaces", detail: "Ctrl+C"}
538			}
539			if len(surfaces) == 0 {
540				return initAction{status: "SKIPPED", target: "surfaces", detail: "no surfaces entered"}
541			}
542			existingCfg.Surfaces = surfaces
543			if err := writeConfigFile(configFile, existingCfg); err != nil {
544				fmt.Fprintf(os.Stderr, "ERROR: failed to write surfaces: %v\n", err)
545				return initAction{status: "FAILED", target: "surfaces", detail: err.Error()}
546			}
547			return initAction{status: "CREATED", target: "surfaces", detail: formatSurfacesSummary(surfaces, nil)}
548		default:
549			// "redetect" — run full detection + inference pipeline
550			return runNewSurfaceDetection(projectRoot, configFile)
551		}
552	}
