559	func runNewSurfaceDetectionImpl(projectRoot, configFile string) initAction {
560		// Run TUI confirmation (detection + display + user interaction)
561		surfaces, sources, cancelled := askSurfaceConfirmation(projectRoot)
562		if cancelled {
