573	// writeSurfacesToConfig writes surfaces to the config file.
574	// Source annotations are NOT persisted — only surface types are written.
575	// Sources are used only for the detail string in the init summary.
576	func writeSurfacesToConfig(configFile string, surfaces forgeconfig.SurfacesMap, sources forgeconfig.SourcesMap) initAction {
577		// Read config from the directory containing the config file
578		projectRoot := filepath.Dir(filepath.Dir(configFile))
579		cfg, err := forgeconfig.ReadConfig(projectRoot)
580		if err != nil || cfg == nil {
581			cfg = &forgeconfig.Config{}
582		}
583	
584		cfg.Surfaces = surfaces
585		if err := writeConfigFile(configFile, cfg); err != nil {
586			fmt.Fprintf(os.Stderr, "ERROR: failed to write surfaces: %v\n", err)
587			return initAction{status: "FAILED", target: "surfaces", detail: err.Error()}
588		}
589	
590		return initAction{status: "CREATED", target: "surfaces", detail: formatSurfacesSummary(surfaces, sources)}
591	}
