59	// AllCompletedResult holds context for running tests after all tasks complete.
60	type AllCompletedResult struct {
61		FeatureSlug string
62		ProjectRoot string
63		DocsOnly    bool // true if no implementation or fix tasks exist
64	}
65	
66	// checkAllCompleted verifies all tasks are done and returns test context.
67	// Returns (nil, nil) when tasks are not all done — caller should exit silently.
68	// Returns (nil, error) for infrastructure failures (no project, no feature).
69	func checkAllCompleted(verbose bool) (*AllCompletedResult, error) {
70		projectRoot, err := project.FindProjectRoot()
71		if err != nil {
72			base.Debugf(verbose, "project root not found: %v", err)
73			return nil, base.ErrProjectNotFound()
74		}
75		base.Debugf(verbose, "project root: %s", projectRoot)
76	
77		featureSlug, err := feature.GetCurrentFeature(projectRoot)
78		if err != nil {
79			base.Debugf(verbose, "feature not found: %v", err)
80			return nil, base.ErrFeatureNotSet()
81		}
82		base.Debugf(verbose, "feature: %s", featureSlug)
83	
84		// Guard: only proceed if .forge/state.json signals allCompleted.
85		forgeState := feature.ReadForgeState(projectRoot)
86		if forgeState == nil || !forgeState.AllCompleted {
87			base.Debugf(verbose, "no forge state with allCompleted — skipping")
88			return nil, nil
89		}
90		base.Debugf(verbose, "forge state: feature=%s allCompleted=true", forgeState.Feature)
91	
92		// Consume the state — clear it before proceeding
93		_ = feature.ClearForgeState(projectRoot)
94	
95		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
96		index, err := task.LoadIndex(indexPath)
97		if err != nil {
98			base.Debugf(verbose, "index.json not found: %s (%v)", indexPath, err)
99			return nil, nil
100		}
101		base.Debugf(verbose, "loaded index: %d tasks", index.TaskCount())
102	
103		// All tasks must be completed or skipped (rejected does not count as done)
104		for _, t := range index.TasksMap() {
105			if t.Status != types.StatusCompleted && t.Status != types.StatusSkipped {
106				base.Debugf(verbose, "task %s is %s — not all done", t.ID, t.Status)
107				return nil, nil
108			}
109		}
110	
111		return &AllCompletedResult{
112			FeatureSlug: featureSlug,
113			ProjectRoot: projectRoot,
114			DocsOnly:    isDocsOnly(index),
115		}, nil
116	}
117	
118	// isDocsOnly returns true if no task has a testable runtime behavior type.
119	// Docs-only features change only markdown files — no compile/test needed.
120	// Unlike needsTestPipeline in pkg/task, this checks ALL tasks including auto-generated ones.
121	func isDocsOnly(index *task.TaskIndex) bool {
122		for _, t := range index.TasksMap() {
123			if task.IsTestableType(t.Type) {
124				return false
125			}
126		}
127		return true
128	}
