199	// runTestRegression runs the full test regression suite when a justfile with
200	// a test recipe is present. When surfaces are configured in .forge/config.yaml,
201	// it orchestrates per-surface lifecycle (dev→probe→test→teardown for web/api/mobile;
202	// test→teardown for cli/tui). Falls back to legacy behavior when no surfaces configured.
203	// Returns an error when a gate failure is detected, nil otherwise.
204	func runTestRegression(projectRoot, featureSlug string) error {
205		if !just.HasJustfile(projectRoot) || !just.HasRecipe(projectRoot, "test") {
206			return nil
207		}
208	
209		// Detect surface types from config.
210		surfaces, _ := forgeconfig.ReadSurfaces(projectRoot)
211		surfaceTypes := forgeconfig.SurfaceTypes(surfaces)
212	
213		if len(surfaceTypes) == 0 {
214			// No surfaces configured — fall back to legacy behavior.
215			return runTestRegressionLegacy(projectRoot, featureSlug)
216		}
217	
218		// Surface-aware orchestration: run lifecycle per surface type.
219		return runTestRegressionSurface(projectRoot, featureSlug, surfaceTypes)
220	}
