270	// runTestRegressionSurface orchestrates per-surface-type lifecycle sequences.
271	// For each unique surface type, runs the appropriate sequence:
272	//   - web/api: dev → probe → test → teardown (full lifecycle)
273	//   - mobile: dev → probe → test-setup → test → teardown (full lifecycle with mobile setup)
274	//   - cli/tui: test → teardown (simplified)
275	//
276	// Surfaces of the same type share a single lifecycle (dev/probe run once per type).
277	// Teardown is mandatory regardless of prior step success/failure.
278	func runTestRegressionSurface(projectRoot, featureSlug string, surfaceTypes []string) error {
279		var lastErr error
280		for _, surfaceType := range surfaceTypes {
281			fmt.Fprintf(os.Stderr, "--- Running surface orchestration for %s ---\n", surfaceType)
282			result := runSurfaceLifecycle(projectRoot, surfaceType)
283			if !result.success {
284				errorDocPath := feature.TestResultsDir + "/" + feature.TestOutputFileName
285				if result.output != "" {
286					if err := testrunner.WriteRegressionRawOutput(projectRoot, result.output); err != nil {
287						fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
288					}
289				}
290				fixID, fixErr := addRegressionFixTasks(projectRoot, featureSlug, result.output, errorDocPath)
291				if fixErr != nil {
292					fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
293				}
294				lastErr = handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(result.output, conciseErrorMaxLines), true)
295			}
296		}
297		return lastErr
298	}
