392	// runTeardown executes the teardown recipe for a surface type.
393	// Errors are logged but never fail the lifecycle — teardown is best-effort cleanup.
394	func runTeardown(projectRoot, surfaceType string) {
395		recipe := resolveRecipe(projectRoot, surfaceType, "teardown")
396		if recipe != "" {
397			fmt.Fprintf(os.Stderr, "  Running teardown (just %s)...\n", recipe)
398			output, success := just.RunCapture(projectRoot, "just", recipe)
399			if !success {
400				fmt.Fprintf(os.Stderr, "  WARNING: teardown failed (just %s)\n", recipe)
401				if output != "" {
402					fmt.Fprintf(os.Stderr, "  %s\n", just.ExtractConciseError(output, 3))
403				}
404			}
405		}
406	}
