487	// runUnitTestStep runs unit tests with a retry-once policy for transient failures.
488	// On first failure, tests are re-run once. If retry passes, a warning is logged and
489	// no fix task is created. If retry also fails, a fix task is created with both outputs.
490	// Returns (passed, fixTaskID, error).
491	func runUnitTestStep(projectRoot, featureSlug string, runTest testRunFunc) (bool, string, error) {
492		unitOutput, unitSuccess := runTest(projectRoot)
493		if unitSuccess {
494			return true, "", nil
495		}
496	
497		// First attempt failed — retry once.
498		fmt.Fprintln(os.Stderr, "WARNING: unit tests failed on first attempt, retrying once...")
499		retryOutput, retrySuccess := runTest(projectRoot)
500		if retrySuccess {
501			fmt.Fprintln(os.Stderr, "WARNING: unit tests passed on retry (transient failure)")
502			return true, "", nil
503		}
504	
505		// Both attempts failed — write combined output and create fix task.
506		fmt.Fprintln(os.Stderr, "ERROR: unit tests failed (retried once, both attempts failed)")
507		errorDocPath := feature.TestResultsDir + "/" + feature.UnitTestOutputFileName
508		combinedOutput := fmt.Sprintf(
509			"retried once, both attempts failed\n\n=== First attempt ===\n%s\n\n=== Retry attempt ===\n%s",
510			unitOutput, retryOutput,
511		)
512		if combinedOutput != "" {
513			if err := testrunner.WriteUnitTestRawOutput(projectRoot, combinedOutput); err != nil {
514				fmt.Fprintf(os.Stderr, "WARNING: failed to write unit test output: %v\n", err)
515			}
516		}
517	
518		fixID, fixErr := addFixTask(projectRoot, featureSlug, "unit-test", combinedOutput, errorDocPath)
519		return false, fixID, fixErr
520	}
