522	// requireSurfaceInference wraps inferSurface with a hard-failure policy.
523	// When surface inference fails (returns empty key+type), it returns an error
524	// with guidance to run `forge surfaces detect`.
525	// This is the hard-constraint entry point used by addSingleFixTask.
526	// To revert to soft behavior, replace the call with inferSurface and use empty strings.
527	func requireSurfaceInference(projectRoot, sourceFiles string) (surfaceKey, surfaceType string, err error) {
528		key, typ := inferSurface(projectRoot, sourceFiles)
529		if key == "" && typ == "" {
530			return "", "", fmt.Errorf("surface inference failed: no surfaces configured or no match for source files %q. Run 'forge surfaces detect' to configure surfaces", sourceFiles)
531		}
532		return key, typ, nil
533	}
534	
535	// inferSurface attempts to determine the surface-key and surface-type for a
536	// fix-task by querying forge surfaces with all extracted source file paths.
537	// Returns ("", "") on any failure (no surfaces configured, no match, parse error)
538	// — the caller falls back to empty values and fix-task creation proceeds unblocked.
539	// Uses all source files (not just the first) to correctly handle multi-surface projects
540	// where different files may belong to different surfaces.
541	func inferSurface(projectRoot, sourceFiles string) (surfaceKey, surfaceType string) {
542		surfaces, err := forgeconfig.ReadSurfaces(projectRoot)
543		if err != nil || len(surfaces) == 0 {
544			return "", ""
545		}
546	
547		// Parse all source file paths from the comma-separated list.
548		// sourceFiles may be "See error output for affected files" when no files found.
549		if sourceFiles == "" || strings.HasPrefix(sourceFiles, "See error") {
550			return "", ""
551		}
552	
553		var files []string
554		for _, part := range strings.Split(sourceFiles, ",") {
555			f := strings.TrimSpace(part)
556			if f != "" {
557				files = append(files, f)
558			}
559		}
560		if len(files) == 0 {
561			return "", ""
562		}
563	
564		// Try each file until one matches a configured surface.
565		for _, file := range files {
566			match, err := forgeconfig.MatchSurface(surfaces, file)
567			if err == nil {
568				return match.Key, match.Type
569			}
570		}
571		return "", ""
572	}
573	
574	// sourceFileRe matches source file paths followed by :line or :line:col patterns.
575	var sourceFileRe = regexp.MustCompile(`([\w][\w./-]*\.\w{1,10})(?::\d+){1,2}`)
576	
577	// sourceExts is a whitelist of source code extensions for file extraction.
578	var sourceExts = map[string]bool{
579		".go": true, ".ts": true, ".js": true, ".tsx": true, ".jsx": true,
580		".py": true, ".rs": true, ".java": true, ".rb": true,
581		".c": true, ".cpp": true, ".h": true, ".hpp": true,
582		".css": true, ".scss": true, ".html": true, ".sql": true,
583		".vue": true, ".svelte": true,
584	}
585	
586	// extractSourceFiles parses error output and returns comma-separated file paths.
587	func extractSourceFiles(output string) string {
588		seen := make(map[string]bool)
589		var files []string
590		for _, match := range sourceFileRe.FindAllStringSubmatch(output, -1) {
591			path := strings.TrimPrefix(match[1], "./")
592			if path == "" || seen[path] {
593				continue
594			}
595			if !sourceExts[filepath.Ext(path)] {
596				continue
597			}
598			seen[path] = true
599			files = append(files, path)
600		}
601	
602		if len(files) > maxSourceFiles {
603			files = files[:maxSourceFiles]
604		}
605		if len(files) == 0 {
606			return "See error output for affected files"
607		}
608		return strings.Join(files, ", ")
609	}
