611	// isTestFile checks if a filename matches Go test file naming convention (*_test.go).
612	func isTestFile(filename string) bool {
613		return strings.HasSuffix(filename, "_test.go")
614	}
615	
616	// extractFileLineMap extracts a mapping from test file paths to their related output lines.
617	// Only files with direct --- FAIL: entries (primary files) get independent map entries.
618	// Stack-trace-only references are excluded from independent entries but their lines
619	// appear in the primary file's context via line matching.
620	func extractFileLineMap(output string) map[string][]string {
621		result := make(map[string][]string)
622		if output == "" {
623			return result
624		}
625	
626		allLines := strings.Split(output, "\n")
627	
628		// Step 1: Collect primary files (first test file reference in each --- FAIL: block).
629		primaryFiles := make(map[string]bool)
630		inFailBlock := false
631		foundPrimary := false
632		for _, line := range allLines {
633			if strings.HasPrefix(line, "--- FAIL:") {
634				inFailBlock = true
635				foundPrimary = false
636				continue
637			}
638			if inFailBlock {
639				if strings.HasPrefix(line, "    ") || strings.HasPrefix(line, "\t") {
640					if !foundPrimary {
641						for _, match := range sourceFileRe.FindAllStringSubmatch(line, -1) {
642							path := strings.TrimPrefix(match[1], "./")
643							if isTestFile(path) {
644								primaryFiles[path] = true
645								foundPrimary = true
646								break
647							}
648						}
649					}
650				} else {
651					inFailBlock = false
652					foundPrimary = false
653				}
654			}
655		}
656	
657		if len(primaryFiles) == 0 {
658			return result
659		}
660	
661		// Step 2: For each line, check if it contains any primary file reference.
662		// Add context window (±2 lines) for matched lines.
663		lineSet := make(map[string]map[int]bool)
664		for file := range primaryFiles {
665			lineSet[file] = make(map[int]bool)
666		}
667	
668		for i, line := range allLines {
669			for _, match := range sourceFileRe.FindAllStringSubmatch(line, -1) {
670				path := strings.TrimPrefix(match[1], "./")
671				if primaryFiles[path] {
672					for j := i - 2; j <= i+2; j++ {
673						if j >= 0 && j < len(allLines) {
674							lineSet[path][j] = true
675						}
676					}
677				}
678			}
679		}
680	
681		// Step 3: Convert to sorted lines per file.
682		for file, indices := range lineSet {
683			if len(indices) == 0 {
684				continue
685			}
686			sorted := make([]int, 0, len(indices))
687			for idx := range indices {
688				sorted = append(sorted, idx)
689			}
690			sort.Ints(sorted)
691			lines := make([]string, 0, len(sorted))
692			for _, idx := range sorted {
693				lines = append(lines, allLines[idx])
694			}
695			result[file] = lines
696		}
697	
698		return result
699	}
