701	// countFixTasks counts active (non-terminal) fix-tasks for a step.
702	// A fix-task is identified by having a title with the prefix "fix <step>:".
703	// Terminal statuses (completed, rejected, skipped) are excluded from the count.
704	// This ensures the fix-task cap reflects work-in-progress only.
705	func countFixTasks(index *task.TaskIndex, step string) int {
706		count := 0
707		prefix := "fix " + step + ":"
708		for _, t := range index.TasksMap() {
709			if !strings.HasPrefix(t.Title, prefix) {
710				continue
711			}
712			// Exclude terminal statuses
713			if t.Status == types.StatusCompleted || t.Status == types.StatusRejected || t.Status == types.StatusSkipped {
714				continue
715			}
716			count++
717		}
718		return count
719	}
