721	// fixTypeFromStep returns the deterministic task type for a quality gate failure step.
722	// compile/test failures → TypeCodingFix, fmt/lint failures → TypeCodingCleanup.
723	func fixTypeFromStep(step string) string {
724		switch step {
725		case "compile", "unit-test", "test":
726			return task.TypeCodingFix
727		case "fmt", "lint":
728			return task.TypeCodingCleanup
729		default:
730			return task.TypeCodingFix
731		}
732	}
