734	// addFixTask creates fix tasks grouped by test suite (directory) using the same
735	// internal API as `forge task add`. Source files are extracted from the output and
736	// grouped by directory. Each directory group becomes a separate fix-task, enabling
737	// parallel execution and bounded scope. Returns the first task ID on success.
738	// Returns ("", error) on failure: template not found, task add failure, markdown creation failure, or cap exceeded.
739	func addFixTask(projectRoot, featureSlug, step, output, errorDocPath string) (string, error) {
740		sourceFiles := extractSourceFiles(output)
741	
742		// Group source files by directory for parallel execution.
743		groups := groupFilesByDir(sourceFiles)
744	
745		// If no meaningful groups (e.g. "See error output" fallback), create a single task.
746		if len(groups) == 0 {
747			return addSingleFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath)
748		}
749	
750		// One task per directory group.
751		var firstID string
752		for _, group := range groups {
753			id, err := addSingleFixTask(projectRoot, featureSlug, step, group, output, errorDocPath)
754			if err != nil {
755				// If a group fails (e.g. cap reached), return the error.
756				// Already-created tasks remain in the index.
757				return firstID, err
758			}
759			if firstID == "" {
760				firstID = id
761			}
762		}
763		return firstID, nil
764	}
765	
766	// groupFilesByDir splits comma-separated source files into groups by directory.
767	// Files in the same directory stay in one group. Returns nil if files is empty
768	// or the fallback message.
769	func groupFilesByDir(files string) []string {
770		if files == "" || strings.HasPrefix(files, "See error") {
771			return nil
772		}
773	
774		dirMap := make(map[string][]string)
775		for _, f := range strings.Split(files, ",") {
776			f = strings.TrimSpace(f)
777			if f == "" {
778				continue
779			}
780			dir := filepath.Dir(f)
781			dirMap[dir] = append(dirMap[dir], f)
782		}
783	
784		if len(dirMap) <= 1 {
785			// All files in one directory (or no files) — single group.
786			return nil
787		}
788	
789		var groups []string
790		for _, dirFiles := range dirMap {
791			groups = append(groups, strings.Join(dirFiles, ", "))
792		}
793		return groups
794	}
