796	// conciseError extracts all "--- FAIL:" lines from output for test failures.
797	// Falls back to ExtractConciseError (tail 10 lines) when no "--- FAIL:" lines
798	// exist (e.g. compile/fmt/lint steps), ensuring the description is never empty.
799	func conciseError(output string) string {
800		if failLines := just.ExtractFailLines(output); failLines != "" {
801			return failLines
802		}
803		return just.ExtractConciseError(output, 10)
804	}
