806	// fixTaskOverride holds optional overrides for createFixTask.
807	// When a field is set, it replaces the default value derived from step/output.
808	// This allows callers (e.g. addRegressionFixTasks) to customize the task
809	// while reusing the shared creation logic.
810	type fixTaskOverride struct {
811		// Title overrides the default title. When empty, the default
812		// "fix <step>: just <step> failure in quality gate" is used.
813		Title string
814		// Description overrides the default description. When empty, the default
815		// description with error doc path and concise error is used.
816		Description string
817		// ExtraVars are merged into the default Vars map, overwriting keys
818		// with the same name (e.g. SOURCE_FILES, TEST_SCRIPT).
819		ExtraVars map[string]string
820	}
821	
822	// createFixTask is the shared helper for creating a single fix task.
823	// It encapsulates: surface inference, opts construction, AddTask,
824	// CreateTaskMarkdown, and EnsureForgeState.
825	//
826	// The caller provides the core parameters (projectRoot, featureSlug, step,
827	// sourceFiles, output, errorDocPath) and optional overrides via fixTaskOverride.
828	// When no overrides are provided, defaults are derived from step and output
829	// (matching the original addSingleFixTask behavior).
830	//
831	// Returns (taskID, nil) on success.
832	// Returns ("", error) on failure: template not found, task add failure,
833	// or markdown creation failure.
834	func createFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath string, overrides ...fixTaskOverride) (string, error) {
835		var ov fixTaskOverride
836		if len(overrides) > 0 {
837			ov = overrides[0]
838		}
839	
840		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
841	
842		// Surface inference with soft-failure policy.
843		// When surfaces are not configured or no match is found, fix-task creation
844		// proceeds with empty surface key/type.
845		surfaceKey, surfaceType := inferSurface(projectRoot, sourceFiles)
846		if surfaceKey == "" && surfaceType == "" {
847			fmt.Fprintln(os.Stderr, "WARNING: surface inference failed: no surfaces configured or no match for source files. Run 'forge surfaces detect' to configure surfaces")
848		}
849	
850		testScript := "just " + step
851	
852		// Derive title: use override if provided, otherwise default.
853		title := ov.Title
854		if title == "" {
855			title = fmt.Sprintf("fix %s: %s failure in quality gate", step, testScript)
856		}
857	
858		// Derive description: use override if provided, otherwise default.
859		description := ov.Description
860		if description == "" {
861			description = fmt.Sprintf(
862				"Quality gate step `%s` failed during quality-gate hook.\n\n"+
863					"Error output saved to: `%s`\n\n"+
864					"Concise error:\n```\n%s\n```",
865				testScript, errorDocPath, conciseError(output),
866			)
867		}
868	
869		// Build opts — Priority/Breaking/EstimatedTime sourced from template defaults
870		// when available (dual-source truth: opts is authoritative, template provides defaults).
871		// SourceTaskID is deliberately empty (project-wide gate has no source task).
872		// Vars["SOURCE_TASK_ID"] is "N/A (project-wide gate)" for template rendering.
873		taskType := fixTypeFromStep(step)
874	
875		// Derive Breaking and EstimatedTime from template defaults (dual-source truth).
876		// For coding.cleanup (fmt/lint failures): Breaking=false, EstimatedTime="15min".
877		// For coding.fix (compile/test failures): Breaking=true, EstimatedTime="30min".
878		breaking := true
879		estimatedTime := "30min"
880		if defs, err := task.GetTaskTemplateDefaults(taskType); err == nil {
881			breaking = defs.Breaking
882			estimatedTime = defs.EstimatedTime
883		}
884	
885		// Build default vars, then merge extra vars from overrides.
886		vars := map[string]string{
887			"SOURCE_FILES":   sourceFiles,
888			"TEST_SCRIPT":    testScript,
889			"TEST_RESULTS":   errorDocPath,
890			"SOURCE_TASK_ID": "N/A (project-wide gate)",
891		}
892		for k, v := range ov.ExtraVars {
893			vars[k] = v
894		}
895	
896		opts := task.AddTaskOpts{
897			Title:         title,
898			Priority:      string(types.PriorityP0),
899			EstimatedTime: estimatedTime,
900			Breaking:      breaking,
901			Description:   description,
902			Template:      taskType,
903			Type:          taskType,
904			SurfaceKey:    surfaceKey,
905			SurfaceType:   surfaceType,
906			Vars:          vars,
907		}
908	
909		tasksDir := filepath.Join(projectRoot, feature.GetFeatureTasksDir(featureSlug))
910	
911		if _, err := task.GetTaskTemplate(opts.Template); err != nil {
912			return "", fmt.Errorf("template %q not found: %w", opts.Template, err)
913		}
914		if defs, err := task.GetTaskTemplateDefaults(opts.Template); err == nil && defs.IDPrefix != "" {
915			opts.IDPrefix = defs.IDPrefix
916		}
917	
918		id, err := task.AddTask(indexPath, opts)
919		if err != nil {
920			return "", fmt.Errorf("failed to add fix task: %w", err)
921		}
922	
923		opts.ID = id
924	
925		if err := task.CreateTaskMarkdown(tasksDir, id+".md", opts); err != nil {
926			return "", fmt.Errorf("failed to create fix task file %s: %w", id+".md", err)
927		}
928	
929		if err := feature.EnsureForgeState(projectRoot, featureSlug); err != nil {
930			fmt.Fprintf(os.Stderr, "WARNING: failed to update .forge/state.json: %v\n", err)
931		}
932	
933		fmt.Fprintf(os.Stderr, "Fix task %s added (P0, breaking=%v)\n", id, breaking)
934		return id, nil
935	}
