937	// addRegressionFixTasks creates independent fix tasks for each failing test file
938	// extracted from the regression output. It uses extractFileLineMap to identify primary
939	// test files (those with direct --- FAIL: entries) and creates one task per file with
940	// the relevant filtered output lines.
941	//
942	// Soft cap: up to 10 independent tasks + 1 overflow task (files 11-N merged).
943	// Total tasks ≤ 11, NOT subject to maxFixTasksPerStep hard cap.
944	//
945	// Fallback: when extractFileLineMap returns an empty map (no test files identified),
946	// falls back to the existing addFixTask behavior with a structured log warning.
947	//
948	// Returns the first task ID on success, or ("", error) on failure.
949	//
950	//nolint:unparam // errorDocPath is parameterized for API consistency with addFixTask and future callers.
951	func addRegressionFixTasks(projectRoot, featureSlug, output, errorDocPath string) (string, error) {
952		fileLineMap := extractFileLineMap(output)
953	
954		// Fallback: no test files identified — use directory-grouped fix task.
955		if len(fileLineMap) == 0 {
956			fmt.Fprintln(os.Stderr, "WARNING: isTestFile returned zero matches for output, falling back to directory-grouped fix task")
957			return addFixTask(projectRoot, featureSlug, "test", output, errorDocPath)
958		}
959	
960		// Sort files for deterministic ordering.
961		files := make([]string, 0, len(fileLineMap))
962		for f := range fileLineMap {
963			files = append(files, f)
964		}
965		sort.Strings(files)
966	
967		var firstID string
968	
969		// Create tasks for first 10 files (or all if ≤ 10).
970		primaryCount := len(files)
971		if primaryCount > 10 {
972			primaryCount = 10
973		}
974	
975		for i := 0; i < primaryCount; i++ {
976			file := files[i]
977			lines := fileLineMap[file]
978			title := fmt.Sprintf("fix test: %s failure in quality gate", file)
979			description := fmt.Sprintf(
980				"Quality gate test regression failed.\n\n"+
981					"Test file: `%s`\n\n"+
982					"Error output saved to: `%s`\n\n"+
983					"Relevant output lines:\n```\n%s\n```",
984				file, errorDocPath, strings.Join(lines, "\n"),
985			)
986	
987			id, err := createFixTask(
988				projectRoot, featureSlug, "test", file, output, errorDocPath,
989				fixTaskOverride{
990					Title:       title,
991					Description: description,
992					ExtraVars: map[string]string{
993						"SOURCE_FILES": file,
994						"TEST_SCRIPT":  "just test",
995					},
996				},
997			)
998			if err != nil {
999				return firstID, err
1000			}
1001			if firstID == "" {
1002				firstID = id
1003			}
1004		}
1005	
1006		// Overflow: merge remaining files into one task.
1007		if len(files) > 10 {
1008			overflowFiles := files[10:]
1009			var overflowLines []string
1010			for _, f := range overflowFiles {
1011				overflowLines = append(overflowLines, fileLineMap[f]...)
1012			}
1013			overflowCount := len(overflowFiles)
1014			title := fmt.Sprintf("fix test: regression overflow (%d files)", overflowCount)
1015			description := fmt.Sprintf(
1016				"Quality gate test regression failed — overflow group.\n\n"+
1017					"Files: %s\n\n"+
1018					"Error output saved to: `%s`\n\n"+
1019					"Relevant output lines:\n```\n%s\n```",
1020				strings.Join(overflowFiles, ", "), errorDocPath, strings.Join(overflowLines, "\n"),
1021			)
1022	
1023			id, err := createFixTask(
1024				projectRoot, featureSlug, "test",
1025				strings.Join(overflowFiles, ", "), output, errorDocPath,
1026				fixTaskOverride{
1027					Title:       title,
1028					Description: description,
1029					ExtraVars: map[string]string{
1030						"SOURCE_FILES": strings.Join(overflowFiles, ", "),
1031						"TEST_SCRIPT":  "just test",
1032					},
1033				},
1034			)
1035			if err != nil {
1036				return firstID, err
1037			}
1038			if firstID == "" {
1039				firstID = id
1040			}
1041		}
1042	
1043		return firstID, nil
1044	}
