1046	// addSingleFixTask creates a single fix task using the same internal API as `forge task add`.
1047	// It performs a cap check (countFixTasks + maxFixTasksPerStep) and delegates to createFixTask.
1048	// Returns (taskID, nil) on success.
1049	// Returns ("", error) on failure: template not found, task add failure, markdown creation failure, or cap exceeded.
1050	func addSingleFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath string) (string, error) {
1051		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
1052	
1053		// Check cap before creating a new fix-task.
1054		index, err := task.LoadIndex(indexPath)
1055		if err != nil {
1056			fmt.Fprintf(os.Stderr, "WARNING: failed to load index for cap check: %v\n", err)
1057			// Proceed without cap check if index can't be loaded.
1058		} else {
1059			active := countFixTasks(index, step)
1060			if active >= maxFixTasksPerStep {
1061				fmt.Fprintf(os.Stderr, "max fix-tasks reached for %s, manual intervention required\n", step)
1062				return "", ErrMaxFixTasks
1063			}
1064		}
1065	
1066		return createFixTask(projectRoot, featureSlug, step, sourceFiles, output, errorDocPath)
1067	}
