58	func runValidateIndex(_ *cobra.Command, args []string) error {
59		var filePath string
60		if len(args) > 0 {
61			filePath = args[0]
62		} else {
63			projectRoot, err := project.FindProjectRoot()
64			if err != nil {
65				base.Exit(base.ErrProjectNotFound())
66			}
67			slug, err := feature.RequireFeature(projectRoot)
68			if err != nil {
69				base.Exit(base.ErrFeatureNotSet())
70			}
71			filePath = filepath.Join(projectRoot, feature.GetFeatureIndexFile(slug))
72		}
73	
74		v := &validator{filePath: filePath}
75		if err := v.run(); err != nil {
