89	func (v *validator) run() error {
90		data, err := os.ReadFile(v.filePath)
91		if err != nil {
92			return base.ErrFileNotFound(v.filePath)
93		}
94	
95		var idx task.TaskIndex
96		if err := json.Unmarshal(data, &idx); err != nil {
97			return base.ErrInvalidJSON(v.filePath, err.Error())
98		}
99	
100		if idx.Feature == "" {
101			return base.NewAIError(base.ErrValidation, "Missing required field", "'feature' field is empty", "Add feature name to index.json", "Add \"feature\": \"<name>\" to index.json")
102		}
103	
104		v.info = append(v.info, fmt.Sprintf("Feature: %s", idx.Feature))
105		v.info = append(v.info, fmt.Sprintf("Tasks: %d", idx.TaskCount()))
106	
107		if idx.PRD == "" && idx.Proposal == "" {
108			v.warnings = append(v.warnings, "Missing 'prd' field")
109		}
110		if idx.Design == "" && idx.Proposal == "" {
111			v.warnings = append(v.warnings, "Missing 'design' field")
112		}
113	
114		// Quick mode: Proposal replaces PRD+Design, flat tasks without phases/gates/summaries
115		v.quickMode = idx.Proposal != "" && idx.PRD == "" && idx.Design == ""
116		if len(idx.StatusEnum) == 0 {
117			v.warnings = append(v.warnings, "Missing 'statusEnum' field — task record/status commands may fail")
118		}
119	
120		v.validateTasks(idx.TasksMap())
121		v.validateDependencies(&idx)
122		v.validateCircularDeps(idx.TasksMap())
123		v.validateFilesExist(idx.Feature, idx.TasksMap())
124		v.validateWildcardSelfDeps(&idx)
125		v.validateGateIntegrity(idx.TasksMap())
126		v.validatePhaseOrder(idx.TasksMap())
127		v.validatePhaseSummaries(idx.TasksMap())
128		v.validateLiveness(&idx)
129		if !v.printResults() {
130			return base.NewAIError(base.ErrValidation, "Validation failed", fmt.Sprintf("%d errors found", len(v.errors)), "Fix errors in index.json", "cat "+v.filePath)
131		}
132		return nil
133	}
