135	func (v *validator) validateTasks(tasks map[string]task.Task) {
136		for key, t := range tasks {
137			if t.ID == "" {
138				v.errors = append(v.errors, fmt.Sprintf("Task '%s': missing 'id'", key))
139			}
140			if t.Title == "" {
141				v.errors = append(v.errors, fmt.Sprintf("Task '%s': missing 'title'", key))
142			}
143			if t.File == "" {
144				v.errors = append(v.errors, fmt.Sprintf("Task '%s': missing 'file'", key))
145			}
146			if t.Status != "" && !validStatus[string(t.Status)] {
147				v.errors = append(v.errors, fmt.Sprintf("Task '%s': invalid status '%s'", key, t.Status))
148			}
149			if t.Priority != "" && !validPriority[string(t.Priority)] {
150				v.errors = append(v.errors, fmt.Sprintf("Task '%s': invalid priority '%s'", key, t.Priority))
151			}
152			switch {
153			case t.Type == "":
154				v.errors = append(v.errors, fmt.Sprintf("Task '%s': missing 'type'", key))
155			case !task.IsValidType(t.Type):
156				v.errors = append(v.errors, fmt.Sprintf("Task '%s': invalid type '%s'", key, t.Type))
157			}
158			// System type interception: non-auto-gen tasks must not use system types
159			if t.Type != "" && task.IsSystemType(t.Type) && !task.IsAutoGenTaskID(t.ID) {
160				v.errors = append(v.errors, fmt.Sprintf("Task '%s': type '%s' is a system-reserved type (reserved: %s)", t.ID, t.Type, task.FormatSystemTypes()))
161			}
162		}
163	}
