165	func (v *validator) validateDependencies(index *task.TaskIndex) {
166		for key, t := range index.TasksMap() {
167			for _, dep := range t.Dependencies {
168				matches, isWildcard := task.ResolveWildcardDep(index, dep)
169				if isWildcard {
170					if len(matches) == 0 {
171						v.errors = append(v.errors, fmt.Sprintf("Task '%s': wildcard '%s' matches no business tasks", key, dep))
172					}
173				} else if _, found := index.ByID(dep); !found {
174					v.errors = append(v.errors, fmt.Sprintf("Task '%s': dependency '%s' not found", key, dep))
175				}
176			}
177		}
178	}
