180	func (v *validator) validateCircularDeps(tasks map[string]task.Task) {
181		graph := make(map[string][]string)
182		taskIDs := make(map[string]bool)
183		for _, t := range tasks {
184			taskIDs[t.ID] = true
185		}
186		for _, t := range tasks {
187			for _, dep := range t.Dependencies {
188				if !strings.HasSuffix(dep, task.IDSuffixWildcard) && taskIDs[dep] {
189					graph[t.ID] = append(graph[t.ID], dep)
190				}
191			}
192		}
193	
194		visited := make(map[string]bool)
195		inStack := make(map[string]bool)
196	
197		var dfs func(id string, path []string) bool
198		dfs = func(id string, path []string) bool {
199			visited[id] = true
200			inStack[id] = true
201			for _, neighbor := range graph[id] {
202				if !visited[neighbor] {
203					if dfs(neighbor, append(path, neighbor)) {
204						return true
205					}
206				} else if inStack[neighbor] {
207					v.errors = append(v.errors, fmt.Sprintf("Circular: %s", strings.Join(append(path, neighbor), " -> ")))
208					return true
209				}
210			}
211			inStack[id] = false
212			return false
213		}
214	
215		for id := range taskIDs {
216			if !visited[id] && dfs(id, []string{id}) {
217				break
218			}
219		}
220	}
