222	func (v *validator) validateFilesExist(featureSlug string, tasks map[string]task.Task) {
223		// Get project root from filePath (which is .../docs/features/<slug>/tasks/index.json)
224		// Go up 4 levels: index.json -> tasks -> <slug> -> features -> docs -> projectRoot
225		projectRoot := filepath.Dir(filepath.Dir(filepath.Dir(filepath.Dir(filepath.Dir(v.filePath)))))
226		tasksDir := filepath.Join(projectRoot, feature.GetFeatureTasksDir(featureSlug))
227	
228		for key, t := range tasks {
229			if t.File == "" {
230				continue
231			}
232			taskFile := filepath.Join(tasksDir, t.File)
233			if _, err := os.Stat(taskFile); os.IsNotExist(err) {
234				v.warnings = append(v.warnings, fmt.Sprintf("Task '%s': file '%s' missing", key, t.File))
235			}
236	
237			// Check for unresolved template placeholders in first-test task files
238			if strings.HasPrefix(t.ID, "T-test-gen-scripts-") {
239				v.validateFirstTestTaskTemplate(taskFile, t.ID, []string{"{{LAST_BUSINESS_TASK_ID}}", "{{T_TEST_1_DEP}}"})
240			}
241		}
