244	// validateFirstTestTaskTemplate checks if a first-test task file has unresolved placeholders.
245	func (v *validator) validateFirstTestTaskTemplate(taskFile string, taskID string, placeholders []string) {
246		data, err := os.ReadFile(taskFile)
247		if err != nil {
248			return // File existence already checked above
249		}
250	
251		content := string(data)
252		for _, ph := range placeholders {
253			if strings.Contains(content, ph) {
254				v.errors = append(v.errors,
255					fmt.Sprintf("Task '%s': file contains unresolved placeholder %s — replace with actual dependency ID", taskID, ph))
256			}
257		}
