400	// V4: Phase summary existence
401	func (v *validator) validatePhaseSummaries(tasks map[string]task.Task) {
402		// Quick mode: flat tasks without phases, summaries, or gates
403		if v.quickMode {
404			return
405		}
406		// Collect phases that have business tasks
407		phasesWithBusiness := make(map[int]bool)
408		for _, t := range tasks {
409			if task.IsBusinessTask(t.ID) {
410				if p := task.GetTaskPhase(t.ID); p > 0 {
411					phasesWithBusiness[p] = true
412				}
413			}
414		}
415	
416		// Check each such phase has a .summary task
417		for phase := range phasesWithBusiness {
418			summaryID := fmt.Sprintf("%d.summary", phase)
419			found := false
420			for _, t := range tasks {
421				if t.ID == summaryID {
422					found = true
423					break
424				}
425			}
426			if !found {
427				v.warnings = append(v.warnings, fmt.Sprintf("Phase %d has business tasks but no '%d.summary' task", phase, phase))
428			}
429		}
430	}
