465	// validateLiveness checks for lifecycle anomalies in blocked tasks.
466	func (v *validator) validateLiveness(index *task.TaskIndex) {
467		for key, t := range index.TasksMap() {
468			if t.Status != types.StatusBlocked {
469				continue
470			}
471	
472			if len(t.Dependencies) == 0 {
473				v.warnings = append(v.warnings,
474					fmt.Sprintf("Task '%s' (%s): blocked with no dependencies (orphaned)", key, t.ID))
475				continue
476			}
477	
478			allDepsCompleted := true
479			hasActiveDep := false
480			for _, dep := range t.Dependencies {
481				matches, isWildcard := task.ResolveWildcardDep(index, dep)
482				if isWildcard {
483					for _, matchID := range matches {
484						if matchID == t.ID {
485							continue
486						}
487						other, _ := index.ByID(matchID)
488						if !task.IsDepSatisfied(string(other.Status)) {
489							allDepsCompleted = false
490							if other.Status == types.StatusPending || other.Status == types.StatusInProgress {
491								hasActiveDep = true
492							}
493						}
494					}
495					continue
496				}
497				depTask, found := index.ByID(dep)
498				if !found {
499					v.errors = append(v.errors,
500						fmt.Sprintf("Task '%s' (%s): blocked on missing dependency '%s'", key, t.ID, dep))
501					allDepsCompleted = false
502					continue
503				}
504				if task.IsDepSatisfied(string(depTask.Status)) {
505					continue
506				}
507				allDepsCompleted = false
508				if depTask.Status == types.StatusPending || depTask.Status == types.StatusInProgress {
509					hasActiveDep = true
510				}
511			}
512	
513			if allDepsCompleted {
514				v.warnings = append(v.warnings,
515					fmt.Sprintf("Task '%s' (%s): blocked but all dependencies resolved (stale, should be pending)", key, t.ID))
516			} else if !hasActiveDep {
517				v.warnings = append(v.warnings,
518					fmt.Sprintf("Task '%s' (%s): blocked with no path to resolution (all deps blocked or missing)", key, t.ID))
519			}
520		}
521	}
