15		tea "github.com/charmbracelet/bubbletea"
16		"github.com/charmbracelet/lipgloss"
17	)
18	
19	// treeNode represents a task in the dependency tree hierarchy.
20	type treeNode struct {
21		Task     task.Task
22		Children []*treeNode
23		Expanded bool
24	}
25	
26	// flatItem is a flattened tree node used for rendering and navigation.
27	type flatItem struct {
28		Node  *treeNode
29		Depth int
30	}
31	
32	// forestOption configures forest building.
33	type forestOption struct {
34		sortByID bool
35	}
36	
37	// forestOptionFunc is a functional option for buildForest.
38	type forestOptionFunc func(*forestOption)
39	
40	// withSortByID sets whether siblings are sorted by natural ID.
41	func withSortByID(v bool) forestOptionFunc {
42		return func(o *forestOption) {
43			o.sortByID = v
44		}
45	}
46	
47	// buildForest constructs a tree from the task index using dependency edges.
48	// Root nodes are tasks with no dependencies (or whose deps are missing/cyclic).
49	func buildForest(idx *task.TaskIndex, opts ...forestOptionFunc) []*treeNode {
50		o := forestOption{}
51		for _, fn := range opts {
52			fn(&o)
53		}
54	
55		tasks := idx.TasksMap()
56	
57		// Use Task.ID as the canonical key throughout (map key may differ from Task.ID).
58		// Build node map keyed by Task.ID.
59		nodeMap := make(map[string]*treeNode, len(tasks))
60		for _, t := range tasks {
61			nodeMap[t.ID] = &treeNode{Task: t}
62		}
63	
64		// Expand all dependencies (handle wildcards, missing).
65		// Build a child -> parent mapping using Task.ID keys.
66		childToParents := make(map[string][]string)
67		allIDs := make([]string, 0, len(tasks))
68		for _, t := range tasks {
69			allIDs = append(allIDs, t.ID)
70		}
71	
72		for _, id := range allIDs {
73			t, _ := idx.ByID(id)
74			deps := expandDepsForTree(idx, t.Dependencies, id)
75			for _, dep := range deps {
76				if _, found := idx.ByID(dep); found {
77					childToParents[id] = append(childToParents[id], dep)
78				}
79			}
80		}
81	
82		// Attach children to parents.
83		for childID, parents := range childToParents {
84			child := nodeMap[childID]
85			for _, parentID := range parents {
86				parent := nodeMap[parentID]
87				parent.Children = append(parent.Children, child)
88			}
89		}
90	
91		// Find roots: tasks that have no parents in the childToParents map.
92		// A task is a root if no other task lists it as a child via its expanded deps.
93		hasParent := make(map[string]bool)
94		for childID := range childToParents {
95			hasParent[childID] = true
96		}
97	
98		// Detect cycle nodes: tasks in cycles have no reachable root.
99		// Use TopologicalSort to find cycles (returns Task.ID values).
100		_, cycles, _ := task.TopologicalSort(idx)
101		cycleSet := make(map[string]bool, len(cycles))
102		for _, c := range cycles {
103			cycleSet[c] = true
104		}
105	
106		// For cycle nodes, detach their children to avoid infinite recursion.
107		// Cycle nodes appear as roots without their cyclic children.
108		for id := range cycleSet {
109			nodeMap[id].Children = nil
110		}
111	
112		// Remove cyclic edges from non-cycle nodes' children.
113		for _, id := range allIDs {
114			if !cycleSet[id] {
115				filtered := make([]*treeNode, 0, len(nodeMap[id].Children))
116				for _, child := range nodeMap[id].Children {
117					if !cycleSet[child.Task.ID] {
118						filtered = append(filtered, child)
119					}
120				}
121				nodeMap[id].Children = filtered
122			}
123		}
124	
125		var roots []*treeNode
126		for _, id := range allIDs {
127			if !hasParent[id] || cycleSet[id] {
128				roots = append(roots, nodeMap[id])
129			}
130		}
131	
132		// Sort roots.
133		sortTreeNodes(roots, o.sortByID)
134	
135		// Sort all children recursively.
136		sortChildrenRecursive(roots, o.sortByID)
137	
138		// Expand root nodes by default.
139		for _, r := range roots {
140			r.Expanded = len(r.Children) > 0
141		}
142	
143		return roots
144	}
145	
146	// expandDepsForTree expands a task's dependencies for tree building.
147	// Similar to pkg/task.expandDeps but simplified (no missingSet tracking).
148	func expandDepsForTree(idx *task.TaskIndex, deps []string, selfID string) []string {
149		seen := make(map[string]bool)
150		var result []string
151	
152		for _, dep := range deps {
153			matches, isWildcard := task.ResolveWildcardDep(idx, dep)
154			if isWildcard {
155				for _, matchID := range matches {
156					if !seen[matchID] {
157						seen[matchID] = true
158						result = append(result, matchID)
159					}
160				}
161			} else {
162				if dep == selfID {
163					// Self-reference: skip in tree (would create cycle)
164					continue
165				}
166				if _, found := idx.ByID(dep); found {
167					if !seen[dep] {
168						seen[dep] = true
169						result = append(result, dep)
170					}
171				}
172			}
173		}
174		return result
175	}
176	
177	// sortTreeNodes sorts a slice of tree nodes.
178	// By default, uses natural ID order (topo-based from buildForest).
179	// If sortByID is true, uses CompareVersionIDs for natural ordering.
180	func sortTreeNodes(nodes []*treeNode, sortByID bool) {
181		sort.SliceStable(nodes, func(i, j int) bool {
182			if sortByID {
183				return task.CompareVersionIDs(nodes[i].Task.ID, nodes[j].Task.ID)
184			}
185			// Default: same as topological order (already sorted by buildForest)
186			return task.CompareVersionIDs(nodes[i].Task.ID, nodes[j].Task.ID)
187		})
188	}
189	
190	// sortChildrenRecursive sorts children at all levels.
191	func sortChildrenRecursive(roots []*treeNode, sortByID bool) {
192		for _, r := range roots {
193			sortTreeNodes(r.Children, sortByID)
194			sortChildrenRecursive(r.Children, sortByID)
195		}
196	}
197	
198	// statusSymbol returns the symbol for a task status.
199	func statusSymbol(status string) string {
200		switch types.Status(status) {
201		case types.StatusCompleted:
202			return "✓"
203		case types.StatusInProgress:
204			return "~"
205		case types.StatusBlocked, types.StatusRejected:
206			return "✗"
207		default:
208			// Non-canonical error-like statuses (e.g. "failed") also get error symbol
209			if status == "failed" {
210				return "✗"
211			}
212			return "○"
213		}
214	}
215	
216	// statusColor returns the lipgloss color name for a task status.
217	func statusColor(status string) string {
218		switch types.Status(status) {
219		case types.StatusCompleted:
220			return "green"
221		case types.StatusInProgress:
222			return "yellow"
223		case types.StatusBlocked, types.StatusRejected:
224			return "red"
225		default:
226			// Non-canonical error-like statuses (e.g. "failed") also get red
227			if status == "failed" {
228				return "red"
229			}
230			return "gray"
231		}
232	}
233	
234	// canUseTUI determines whether the terminal supports TUI mode.
235	func canUseTUI(isTerminal bool, termEnv string) bool {
236		if !isTerminal {
237			return false
238		}
239		if termEnv == "" || termEnv == "dumb" {
240			return false
241		}
242		return true
243	}
244	
245	// flattenTree returns a flat list of visible tree items for rendering.
246	func flattenTree(roots []*treeNode, allExpanded bool) []flatItem {
247		var items []flatItem
248		for _, root := range roots {
249			flattenNode(root, 0, &items, allExpanded)
250		}
251		return items
252	}
253	
254	// flattenNode recursively flattens a tree node and its visible children.
255	func flattenNode(node *treeNode, depth int, items *[]flatItem, allExpanded bool) {
256		*items = append(*items, flatItem{Node: node, Depth: depth})
257		if node.Expanded || allExpanded {
258			for _, child := range node.Children {
259				flattenNode(child, depth+1, items, allExpanded)
260			}
261		}
262	}
263	
264	// renderTreePlain renders the tree as plain text (no ANSI codes).
265	// Used for non-TTY output and testing.
266	func renderTreePlain(roots []*treeNode) string {
267		var sb strings.Builder
268		items := flattenTree(roots, true)
269		for _, item := range items {
270			indent := strings.Repeat("  ", item.Depth)
271			sym := statusSymbol(string(item.Node.Task.Status))
272			title := item.Node.Task.Title
273			id := item.Node.Task.ID
274			fmt.Fprintf(&sb, "%s%s %s: %s\n", indent, sym, id, title)
275		}
276		return sb.String()
277	}
