279	// --- bubbletea TUI model ---
280	
281	// treeModel is the bubbletea Model for the task tree TUI.
282	type treeModel struct {
283		roots    []*treeNode
284		items    []flatItem
285		cursor   int
286		useColor bool
287		quitting bool
288		width    int
289		height   int
290	}
291	
292	// newTreeModel creates a new TUI tree model.
293	func newTreeModel(roots []*treeNode, useColor bool) treeModel {
294		items := flattenTree(roots, false)
295		if len(items) == 0 {
296			return treeModel{
297				roots:    roots,
298				items:    items,
299				useColor: useColor,
300			}
301		}
302		return treeModel{
303			roots:    roots,
304			items:    items,
305			cursor:   0,
306			useColor: useColor,
307			width:    80,
308			height:   24,
309		}
310	}
311	
312	// Init implements bubbletea.Model.
313	func (m treeModel) Init() tea.Cmd {
314		return nil
315	}
316	
317	// Update implements bubbletea.Model.
318	func (m treeModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
319		switch msg := msg.(type) {
320		case tea.WindowSizeMsg:
321			m.width = msg.Width
322			m.height = msg.Height
323			return m, nil
324		case tea.KeyMsg:
325			switch {
326			case key.Matches(msg, quitKeys):
327				m.quitting = true
328				return m, tea.Quit
329			case key.Matches(msg, upKeys):
330				if m.cursor > 0 {
331					m.cursor--
332				}
333			case key.Matches(msg, downKeys):
334				if m.cursor < len(m.items)-1 {
335					m.cursor++
336				}
337			case key.Matches(msg, expandKeys):
338				if m.cursor < len(m.items) {
339					node := m.items[m.cursor].Node
340					if len(node.Children) > 0 {
341						node.Expanded = true
342						m.items = flattenTree(m.roots, false)
343					}
344				}
345			case key.Matches(msg, collapseKeys):
346				if m.cursor < len(m.items) {
347					node := m.items[m.cursor].Node
348					if len(node.Children) > 0 {
349						node.Expanded = false
350						m.items = flattenTree(m.roots, false)
351					}
352				}
353			}
354		}
355		return m, nil
356	}
357	
358	// View implements bubbletea.Model.
359	func (m treeModel) View() string {
360		if m.quitting || len(m.items) == 0 {
361			return ""
362		}
363	
364		var sb strings.Builder
365	
366		// Header
367		fmt.Fprintf(&sb, "Task Dependency Tree (q: quit, ↑↓: navigate, ←→: collapse/expand)\n\n")
368	
369		// Calculate visible window
370		visibleHeight := m.height - 4 // reserve for header + footer
371		if visibleHeight < 5 {
372			visibleHeight = 5
373		}
374	
375		start := 0
376		end := len(m.items)
377		if end > visibleHeight {
378			// Scroll window around cursor
379			start = m.cursor - visibleHeight/2
380			if start < 0 {
381				start = 0
382			}
383			end = start + visibleHeight
384			if end > len(m.items) {
385				end = len(m.items)
386				start = end - visibleHeight
387				if start < 0 {
388					start = 0
389				}
390			}
391		}
392	
393		for i := start; i < end; i++ {
394			item := m.items[i]
395			indent := strings.Repeat("  ", item.Depth)
396			sym := statusSymbol(string(item.Node.Task.Status))
397			id := item.Node.Task.ID
398			title := item.Node.Task.Title
399	
400			// Expand/collapse indicator
401			expandChar := " "
402			if len(item.Node.Children) > 0 {
403				if item.Node.Expanded {
404					expandChar = "▾"
405				} else {
406					expandChar = "▸"
407				}
408			}
409	
410			// Cursor indicator
411			cursor := " "
412			if i == m.cursor {
413				cursor = ">"
414			}
415	
416			line := fmt.Sprintf("%s %s%s %s %s", cursor, indent, expandChar, sym, formatNodeLine(id, title))
417	
418			if m.useColor {
419				color := statusColor(string(item.Node.Task.Status))
420				styled := lipgloss.NewStyle().Foreground(lipgloss.Color(color)).Render(sym+" "+id) + ": " + title
421				line = fmt.Sprintf("%s %s%s %s", cursor, indent, expandChar, styled)
422			}
423	
424			sb.WriteString(line)
425			sb.WriteString("\n")
426		}
427	
428		// Footer
429		fmt.Fprintf(&sb, "\n%d/%d tasks", m.cursor+1, len(m.items))
430	
431		return sb.String()
432	}
433	
434	// formatNodeLine formats a tree node line as "ID: Title".
435	func formatNodeLine(id, title string) string {
436		return id + ": " + title
437	}
438	
439	// Key bindings.
440	var (
441		quitKeys = key.NewBinding(
442			key.WithKeys("q", "ctrl+c"),
443			key.WithHelp("q", "quit"),
444		)
445		upKeys = key.NewBinding(
446			key.WithKeys("up", "k"),
447			key.WithHelp("↑/k", "move up"),
448		)
449		downKeys = key.NewBinding(
450			key.WithKeys("down", "j"),
451			key.WithHelp("↓/j", "move down"),
452		)
453		expandKeys = key.NewBinding(
454			key.WithKeys("right", "l", "enter"),
455			key.WithHelp("→/l/enter", "expand"),
456		)
457		collapseKeys = key.NewBinding(
458			key.WithKeys("left", "h"),
459			key.WithHelp("←/h", "collapse"),
460		)
461	)
462	
463	// runTreeTUI launches the interactive TUI tree view.
464	func runTreeTUI(roots []*treeNode) error {
465		_, termEnv := getTerminalInfo()
466		useColor := termEnv != "dumb" && termEnv != ""
467	
468		p := tea.NewProgram(
469			newTreeModel(roots, useColor),
470			tea.WithAltScreen(),
471		)
472		_, err := p.Run()
473		return err
474	}
475	
476	// renderTreeFallback renders the tree as plain text for non-TTY environments.
477	// Falls back to table-like output with tree structure.
478	func renderTreeFallback(roots []*treeNode, featureSlug string) string {
479		var sb strings.Builder
480		items := flattenTree(roots, true)
481		fmt.Fprintf(&sb, "%d found  (feature: %s)\n\n", len(items), featureSlug)
482	
483		for _, item := range items {
484			indent := strings.Repeat("  ", item.Depth)
485			sym := statusSymbol(string(item.Node.Task.Status))
486			id := item.Node.Task.ID
487			title := base.TruncateSlug(item.Node.Task.Title, 50)
488			status := item.Node.Task.Status
489			fmt.Fprintf(&sb, "%s%s %s  %-50s  %s\n", indent, sym, id, title, status)
490		}
491	
492		return sb.String()
493	}
494	
495	// getTerminalInfo returns whether stdout is a terminal and the TERM env value.
496	func getTerminalInfo() (isTerminal bool, termEnv string) {
497		fi, err := os.Stdout.Stat()
498		if err != nil {
499			return false, ""
500		}
501		isTerminal = fi.Mode()&os.ModeCharDevice != 0
502		termEnv = os.Getenv("TERM")
503		return isTerminal, termEnv
504	}
