14	)
15	
16	var verifyTaskDoneCmd = &cobra.Command{
17		Use:   "verify-task-done",
18		Short: "Verify task completion before git commit",
19		Long: `Verifies task completion before allowing git commit.
20	
21	Checks:
22	  - Task status is "completed"
23	  - Record file exists (if specified)
24	
25	Exit codes:
26	  0 - All checks passed
27	  2 - Verification failed`,
28		Args: cobra.NoArgs,
29		RunE: runVerifyTaskDone,
30	}
31	
32	func runVerifyTaskDone(_ *cobra.Command, _ []string) error {
33		if err := verifyTaskCompletion(); err != nil {
34			return err
35		}
36		return nil
37	}
38	
39	// verifyTaskCompletion verifies task completion before allowing git commit.
40	// Returns error if task is not completed or record file is missing.
41	func verifyTaskCompletion() error {
42		projectRoot, err := project.FindProjectRoot()
43		if err != nil {
44			return nil // No project context, allow commit
45		}
46	
47		// Get current feature
48		featureSlug, err := feature.GetCurrentFeature(projectRoot)
49		if err != nil {
50			return nil // No feature set, allow commit
51		}
52	
53		// Read state file
54		statePath := feature.GetTaskStatePath(projectRoot, featureSlug)
55		state, err := task.LoadState(statePath)
56		if err != nil {
57			return nil // No state file, allow commit
58		}
59		if state == nil || state.TaskID == "" {
60			return nil // No active task, allow commit
61		}
62	
63		// Load index
64		indexPath := filepath.Join(projectRoot, feature.GetFeatureIndexFile(featureSlug))
65		index, err := task.LoadIndex(indexPath)
66		if err != nil {
67			return fmt.Errorf("cannot read index.json: %w", err)
68		}
69	
70		// Find task and check status
71		var foundTask *task.Task
72		for _, t := range index.TasksMap() {
73			if t.ID == state.TaskID {
74				foundTask = &t
75				break
76			}
77		}
78	
79		if foundTask == nil {
80			return fmt.Errorf("task %s not found in index.json", state.TaskID)
81		}
82	
83		if foundTask.Status != types.StatusCompleted {
84			return fmt.Errorf("task %s status is %q, not completed. Run 'forge task submit' before committing",
85				state.TaskID, foundTask.Status)
86		}
87	
88		// Verify record file exists
89		if foundTask.Record != "" {
90			recordPath := filepath.Join(projectRoot, feature.GetTaskFile(featureSlug, foundTask.Record))
91			if _, err := os.Stat(recordPath); os.IsNotExist(err) {
92				return fmt.Errorf("record file missing: %s. Create it before committing",
93					feature.GetTaskFile(featureSlug, foundTask.Record))
94			}
95		}
96	
97		return nil
98	}
