130	func runQualityGate(_ *cobra.Command, _ []string) error {
131		result, err := checkAllCompleted(qualityGateVerbose)
132		if err != nil {
133			base.Exit(err)
134		}
135		if result == nil {
136			return nil // not all done is normal, exit silently
137		}
138	
139		fmt.Fprintf(os.Stderr, "=== All tasks completed for feature: %s ===\n", result.FeatureSlug)
140	
141		// Docs-only features have no code changes — skip compile/test gates.
142		if result.DocsOnly {
143			fmt.Fprintln(os.Stderr, "Feature is docs-only — skipping quality gate (no implementation or fix tasks)")
144			os.Exit(0)
145		}
146	
147		// NOTE: The legacy promotion model was removed in v3.0.0 in favor of
148		// tag-based test promotion. No pre-run validation is needed here —
149		// runTestRegression handles the full lifecycle per surface type.
150		_ = result.ProjectRoot
151		_ = result.FeatureSlug
152	
153		// Step 1: Quality gate (compile -> fmt -> lint)
154		// Stops at first blocking failure.
155		gateSteps := just.NonBreakingGateSequence()
156		var gateBlockErr error
157		just.RunGate(result.ProjectRoot, "", gateSteps, func(step, output string) {
158			fmt.Fprintf(os.Stderr, "ERROR: %s check failed\n", step)
159			errorDocPath := feature.TestResultsDir + "/" + feature.UnitTestOutputFileName
160			if output != "" {
161				if err := testrunner.WriteUnitTestRawOutput(result.ProjectRoot, "=== "+step+" failure ===\n"+output); err != nil {
162					fmt.Fprintf(os.Stderr, "WARNING: failed to write %s output: %v\n", step, err)
163				}
164			}
165			fixID, fixErr := addFixTask(result.ProjectRoot, result.FeatureSlug, step, output, errorDocPath)
166			if fixErr != nil {
167				fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
168			}
169			gateBlockErr = handleGateFailure(step, errorDocPath, fixID, just.ExtractConciseError(output, conciseErrorMaxLines), fixTypeFromStep(step) == task.TypeCodingFix)
170		})
171		if gateBlockErr != nil {
172			os.Exit(0)
173		}
174	
175		// Step 2: Project-wide unit tests (with retry-once policy)
176		fmt.Fprintln(os.Stderr, "--- Running project-wide tests ---")
177		unitPassed, unitFixID, unitErr := runUnitTestStep(
178			result.ProjectRoot, result.FeatureSlug,
179			testrunner.RunProjectTests,
180		)
181		if unitErr != nil {
182			fmt.Fprintf(os.Stderr, "WARNING: %v\n", unitErr)
183		}
184		if !unitPassed {
185			unitOutput := "" // output already written by runUnitTestStep
186			errorDocPath := feature.TestResultsDir + "/" + feature.UnitTestOutputFileName
187			if err := handleGateFailure("unit-test", errorDocPath, unitFixID, just.ExtractConciseError(unitOutput, conciseErrorMaxLines), true); err != nil {
188				os.Exit(0)
189			}
190		}
191	
192		// Step 3: Full test regression (test scripts in tests/)
193		if err := runTestRegression(result.ProjectRoot, result.FeatureSlug); err != nil {
194			os.Exit(0)
195		}
196		return nil
197	}
