222	// runTestRegressionLegacy is the pre-surface-aware test regression logic.
223	// Runs test-setup (optional), serverprobe health check, then just test.
224	func runTestRegressionLegacy(projectRoot, featureSlug string) error {
225		// Optional setup step — skip regression on failure.
226		if just.HasRecipe(projectRoot, "test-setup") {
227			fmt.Fprintln(os.Stderr, "--- Ensuring test dependencies (just test-setup) ---")
228			setupOutput, setupSuccess := just.RunCapture(projectRoot, "just", "test-setup")
229			if !setupSuccess {
230				fmt.Fprintln(os.Stderr, "WARNING: test-setup failed; skipping test regression")
231				fmt.Fprintln(os.Stderr, "  To retry manually: just test-setup && just test")
232				if setupOutput != "" {
233					if err := testrunner.WriteRegressionRawOutput(projectRoot, "=== test-setup failure ===\n"+setupOutput); err != nil {
234						fmt.Fprintf(os.Stderr, "WARNING: failed to write setup output: %v\n", err)
235					} else {
236						fmt.Fprintln(os.Stderr, "  Setup output saved to "+feature.TestResultsDir+"/"+feature.TestOutputFileName)
237					}
238				}
239				return nil
240			}
241		}
242	
243		// Health check — skip regression if servers aren't ready.
244		if !serverprobe.ProbeServers(projectRoot, "") {
245			fmt.Fprintln(os.Stderr, "WARNING: server health check failed; skipping test regression")
246			fmt.Fprintln(os.Stderr, "  Start dev server and retry: just dev && just test")
247			return nil
248		}
249	
250		// Run the regression suite.
251		fmt.Fprintln(os.Stderr, "--- Running full test regression (just test) ---")
252		regressionOutput, regSuccess := just.RunCapture(projectRoot, "just", "test")
253		if !regSuccess {
254			fmt.Fprintln(os.Stderr, "ERROR: test regression failed")
255			errorDocPath := feature.TestResultsDir + "/" + feature.TestOutputFileName
256			if regressionOutput != "" {
257				if err := testrunner.WriteRegressionRawOutput(projectRoot, regressionOutput); err != nil {
258					fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
259				}
260			}
261			fixID, fixErr := addRegressionFixTasks(projectRoot, featureSlug, regressionOutput, errorDocPath)
262			if fixErr != nil {
263				fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
264			}
265			return handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(regressionOutput, conciseErrorMaxLines), true)
266		}
267		return nil
268	}
