270	// runTestRegressionSurface orchestrates per-surface-type lifecycle sequences.
271	// For each unique surface type, runs the appropriate sequence:
272	//   - web/api: dev → probe → test → teardown (full lifecycle)
273	//   - mobile: dev → probe → test-setup → test → teardown (full lifecycle with mobile setup)
274	//   - cli/tui: test → teardown (simplified)
275	//
276	// Surfaces of the same type share a single lifecycle (dev/probe run once per type).
277	// Teardown is mandatory regardless of prior step success/failure.
278	func runTestRegressionSurface(projectRoot, featureSlug string, surfaceTypes []string) error {
279		var lastErr error
280		for _, surfaceType := range surfaceTypes {
281			fmt.Fprintf(os.Stderr, "--- Running surface orchestration for %s ---\n", surfaceType)
282			result := runSurfaceLifecycle(projectRoot, surfaceType)
283			if !result.success {
284				errorDocPath := feature.TestResultsDir + "/" + feature.TestOutputFileName
285				if result.output != "" {
286					if err := testrunner.WriteRegressionRawOutput(projectRoot, result.output); err != nil {
287						fmt.Fprintf(os.Stderr, "WARNING: failed to write raw-output.txt: %v\n", err)
288					}
289				}
290				fixID, fixErr := addRegressionFixTasks(projectRoot, featureSlug, result.output, errorDocPath)
291				if fixErr != nil {
292					fmt.Fprintf(os.Stderr, "WARNING: %v\n", fixErr)
293				}
294				lastErr = handleGateFailure("test", errorDocPath, fixID, just.ExtractConciseError(result.output, conciseErrorMaxLines), true)
295			}
296		}
297		return lastErr
298	}
299	
300	// lifecycleResult holds the result of a surface lifecycle execution.
301	type lifecycleResult struct {
302		success bool
303		output  string
304	}
305	
306	// needsFullLifecycle returns true for surface types that require dev→probe→test→teardown.
307	// cli and tui surfaces use the simplified test→teardown sequence.
308	func needsFullLifecycle(surfaceType types.SurfaceType) bool {
309		return surfaceType == types.SurfaceWeb || surfaceType == types.SurfaceAPI || surfaceType == types.SurfaceMobile
310	}
311	
312	// resolveRecipe attempts to find a surface-specific recipe (e.g., "web-dev"),
313	// falling back to the generic recipe (e.g., "dev") if not found.
314	// Returns the recipe name to use, or empty string if neither exists.
315	func resolveRecipe(projectRoot, surfaceType, genericRecipe string) string {
316		specificRecipe := surfaceType + "-" + genericRecipe
317		if just.HasRecipe(projectRoot, specificRecipe) {
318			return specificRecipe
319		}
320		if just.HasRecipe(projectRoot, genericRecipe) {
321			return genericRecipe
322		}
323		return ""
324	}
325	
326	// runSurfaceLifecycle executes the per-surface lifecycle sequence.
327	// For web/api: dev → probe → test → teardown
328	// For mobile: dev → probe → mobile-test-setup → test → teardown
329	// For cli/tui: test → teardown
330	// Teardown always executes (via defer-like pattern).
331	func runSurfaceLifecycle(projectRoot, surfaceType string) lifecycleResult {
332		full := needsFullLifecycle(types.SurfaceType(surfaceType))
333	
334		// Phase 1: Dev (full lifecycle only)
335		if full {
336			recipe := resolveRecipe(projectRoot, surfaceType, "dev")
337			if recipe != "" {
338				fmt.Fprintf(os.Stderr, "  Starting dev server (just %s)...\n", recipe)
339				output, success := just.RunCapture(projectRoot, "just", recipe)
340				if !success {
341					fmt.Fprintf(os.Stderr, "  ERROR: dev failed (just %s)\n", recipe)
342					runTeardown(projectRoot, surfaceType)
343					return lifecycleResult{success: false, output: output}
344				}
345			}
346		}
347	
348		// Phase 2: Probe (full lifecycle only)
349		if full {
350			probeRecipe := resolveRecipe(projectRoot, surfaceType, "probe")
351			if !probeWithRetry(projectRoot, probeRecipe, maxProbeRetries, probeRetryInterval) {
352				fmt.Fprintln(os.Stderr, "  ERROR: probe failed after retries")
353				runTeardown(projectRoot, surfaceType)
354				return lifecycleResult{success: false, output: "probe failed: server not responding after 3 retries"}
355			}
356		}
357	
358		// Phase 2b: Mobile test setup (mobile surfaces only)
359		if types.SurfaceType(surfaceType) == types.SurfaceMobile {
360			setupRecipe := resolveRecipe(projectRoot, surfaceType, "test-setup")
361			if setupRecipe != "" {
362				fmt.Fprintf(os.Stderr, "  Running mobile test setup (just %s)...\n", setupRecipe)
363				output, success := just.RunCapture(projectRoot, "just", setupRecipe)
364				if !success {
365					fmt.Fprintf(os.Stderr, "  ERROR: mobile-test-setup failed (just %s)\n", setupRecipe)
366					runTeardown(projectRoot, surfaceType)
367					return lifecycleResult{success: false, output: output}
368				}
369			}
370		}
371	
372		// Phase 3: Test
373		var result lifecycleResult
374		testRecipe := resolveRecipe(projectRoot, surfaceType, "test")
375		if testRecipe != "" {
376			fmt.Fprintf(os.Stderr, "  Running tests (just %s)...\n", testRecipe)
377			output, success := just.RunCapture(projectRoot, "just", testRecipe)
378			result = lifecycleResult{success: success, output: output}
379			if !success {
380				fmt.Fprintln(os.Stderr, "  ERROR: test failed")
381			}
382		} else {
383			result = lifecycleResult{success: true}
384		}
385	
386		// Phase 4: Teardown (always)
387		runTeardown(projectRoot, surfaceType)
388	
389		return result
390	}
391	
392	// runTeardown executes the teardown recipe for a surface type.
393	// Errors are logged but never fail the lifecycle — teardown is best-effort cleanup.
394	func runTeardown(projectRoot, surfaceType string) {
395		recipe := resolveRecipe(projectRoot, surfaceType, "teardown")
396		if recipe != "" {
397			fmt.Fprintf(os.Stderr, "  Running teardown (just %s)...\n", recipe)
398			output, success := just.RunCapture(projectRoot, "just", recipe)
399			if !success {
400				fmt.Fprintf(os.Stderr, "  WARNING: teardown failed (just %s)\n", recipe)
401				if output != "" {
402					fmt.Fprintf(os.Stderr, "  %s\n", just.ExtractConciseError(output, 3))
403				}
404			}
405		}
406	}
407	
408	// probeWithRetry runs the probe recipe with the specified number of retries.
409	// Returns true if the probe succeeds within the retry count.
410	// Returns true (skip) if the probe recipe doesn't exist.
411	// interval is the delay between retries (0 for no delay, useful in tests).
412	func probeWithRetry(projectRoot, probeRecipe string, maxRetries int, interval time.Duration) bool {
413		if probeRecipe == "" {
414			return true // no probe recipe — skip
415		}
416	
417		// Verify the recipe actually exists before retrying.
418		if !just.HasRecipe(projectRoot, probeRecipe) {
419			return true // recipe not found — skip
420		}
421	
422		for attempt := range maxRetries {
423			if attempt > 0 && interval > 0 {
424				fmt.Fprintf(os.Stderr, "  Probe retry %d/%d (waiting %v)...\n", attempt+1, maxRetries, interval)
425				time.Sleep(interval)
426			}
427			fmt.Fprintf(os.Stderr, "  Probing (just %s) attempt %d/%d...\n", probeRecipe, attempt+1, maxRetries)
428			_, success := just.RunCapture(projectRoot, "just", probeRecipe)
429			if success {
430				fmt.Fprintln(os.Stderr, "  Probe succeeded")
431				return true
432			}
433		}
434		return false
435	}
436	
437	// handleGateFailure prints the hook JSON block reason and returns an error
438	// signalling that the gate blocked. The caller (RunE handler) decides exit behavior.
439	// fixID is the ID returned by addFixTask; empty means task creation failed.
440	// breaking indicates whether the fix task blocks downstream tasks.
441	func handleGateFailure(step, errorDocPath, fixID, concise string, breaking bool) error {
442		action := "run `forge task add --type coding.fix` to create one manually, then `forge task claim`"
443		if fixID != "" {
444			action = "run `forge task claim` to pick it up"
445		}
446	
447		guide := map[string]string{
448			"compile":   "fix compilation errors",
449			"lint":      "fix lint errors",
450			"unit-test": "fix failing unit tests",
451			"test":      "fix failing tests",
452		}
453		label := map[string]string{
454			"compile":   "Project compilation",
455			"lint":      "Lint check",
456			"unit-test": "Unit tests",
457			"test":      "Advanced tests",
458		}
459	
460		g := guide[step]
461		if g == "" {
462			g = "fix the issue"
463		}
464		l := label[step]
465		if l == "" {
466			l = testrunner.Capitalize(step) + " check"
467		}
468	
469		var fixMsg string
470		if fixID != "" {
471			fixMsg = fmt.Sprintf("Fix task %s added (P0, breaking=%v)", fixID, breaking)
472		} else {
473			fixMsg = "Failed to add fix task automatically"
474		}
475	
476		reason := fmt.Sprintf(
477			"%s failed in quality-gate hook. %s — %s and %s.\nError output: %s\n%s",
478			l, fixMsg, action, g, errorDocPath, concise)
479	
480		testrunner.PrintHookJSON(map[string]any{
481			"decision": "block",
482			"reason":   reason,
483		})
484		return fmt.Errorf("quality gate blocked: %s", step)
485	}
486	
487	// runUnitTestStep runs unit tests with a retry-once policy for transient failures.
488	// On first failure, tests are re-run once. If retry passes, a warning is logged and
489	// no fix task is created. If retry also fails, a fix task is created with both outputs.
490	// Returns (passed, fixTaskID, error).
491	func runUnitTestStep(projectRoot, featureSlug string, runTest testRunFunc) (bool, string, error) {
492		unitOutput, unitSuccess := runTest(projectRoot)
493		if unitSuccess {
494			return true, "", nil
495		}
496	
497		// First attempt failed — retry once.
498		fmt.Fprintln(os.Stderr, "WARNING: unit tests failed on first attempt, retrying once...")
499		retryOutput, retrySuccess := runTest(projectRoot)
500		if retrySuccess {
501			fmt.Fprintln(os.Stderr, "WARNING: unit tests passed on retry (transient failure)")
502			return true, "", nil
503		}
504	
505		// Both attempts failed — write combined output and create fix task.
506		fmt.Fprintln(os.Stderr, "ERROR: unit tests failed (retried once, both attempts failed)")
507		errorDocPath := feature.TestResultsDir + "/" + feature.UnitTestOutputFileName
508		combinedOutput := fmt.Sprintf(
509			"retried once, both attempts failed\n\n=== First attempt ===\n%s\n\n=== Retry attempt ===\n%s",
510			unitOutput, retryOutput,
511		)
512		if combinedOutput != "" {
513			if err := testrunner.WriteUnitTestRawOutput(projectRoot, combinedOutput); err != nil {
514				fmt.Fprintf(os.Stderr, "WARNING: failed to write unit test output: %v\n", err)
515			}
516		}
517	
518		fixID, fixErr := addFixTask(projectRoot, featureSlug, "unit-test", combinedOutput, errorDocPath)
519		return false, fixID, fixErr
520	}
521	
522	// requireSurfaceInference wraps inferSurface with a hard-failure policy.
523	// When surface inference fails (returns empty key+type), it returns an error
524	// with guidance to run `forge surfaces detect`.
525	// This is the hard-constraint entry point used by addSingleFixTask.
