261	func (v *validator) validateWildcardSelfDeps(index *task.TaskIndex) {
262		for key, t := range index.TasksMap() {
263			for _, dep := range t.Dependencies {
264				matches, isWildcard := task.ResolveWildcardDep(index, dep)
265				if !isWildcard {
266					continue
267				}
268				prefix := strings.TrimSuffix(dep, task.IDSuffixWildcard) + "."
269				if !strings.HasPrefix(t.ID, prefix) || !task.IsBusinessTask(t.ID) {
270					continue
271				}
272				// This task's own ID matches the wildcard. Check if other business tasks also match.
273				others := len(matches) - 1 // subtract self
274				if others == 0 {
275					v.errors = append(v.errors, fmt.Sprintf("Task '%s' (%s): wildcard '%s' only matches itself (self-dependency deadlock)", key, t.ID, dep))
276				} else {
277					v.warnings = append(v.warnings, fmt.Sprintf("Task '%s' (%s): wildcard '%s' matches itself plus %d others (self excluded at runtime, but verify intent)", key, t.ID, dep, others))
278				}
279			}
280		}
281	}
