283	// V2: Gate integrity
284	func (v *validator) validateGateIntegrity(tasks map[string]task.Task) {
285		type gateInfo struct {
286			key string
287			id  string
288		}
289	
290		// Find all gate tasks
291		var gates []gateInfo
292		for key, t := range tasks {
293			if strings.HasSuffix(t.ID, task.IDSuffixGate) && t.Breaking {
294				gates = append(gates, gateInfo{key: key, id: t.ID})
295			}
296		}
297	
298		for _, g := range gates {
299			phase := task.GetTaskPhase(g.id)
300			if phase <= 0 {
301				continue
302			}
303	
304			// Gate N.gate is phase N's exit gate — must depend on N.summary
305			ownSummary := fmt.Sprintf("%d.summary", phase)
306			hasOwnSummary := false
307			for _, t := range tasks {
308				if t.ID == ownSummary {
309					hasOwnSummary = true
310					break
311				}
312			}
313			if hasOwnSummary {
314				found := false
315				for _, dep := range tasks[g.key].Dependencies {
316					if dep == ownSummary {
317						found = true
318						break
319					}
320				}
321				if !found {
322					v.errors = append(v.errors, fmt.Sprintf("Gate '%s' (%s): must depend on own phase summary '%s'", g.key, g.id, ownSummary))
323				}
324			}
325	
326			// Next phase's business tasks must depend on this gate
327			gateID := g.id
328			nextPhase := phase + 1
329			for key, t := range tasks {
330				if !task.IsBusinessTask(t.ID) {
331					continue
332				}
333				if task.GetTaskPhase(t.ID) != nextPhase {
334					continue
335				}
336				// Check if this business task depends on the gate
337				dependsOnGate := false
338				for _, dep := range t.Dependencies {
339					if dep == gateID {
340						dependsOnGate = true
341						break
342					}
343				}
344				if !dependsOnGate {
345					v.errors = append(v.errors, fmt.Sprintf("Task '%s' (%s): must depend on gate '%s'", key, t.ID, gateID))
346				}
347			}
348		}
349	}
350	
351	// V3: Phase order sanity
352	func (v *validator) validatePhaseOrder(tasks map[string]task.Task) {
353		// Quick mode: flat tasks without phases
354		if v.quickMode {
355			return
356		}
357		// Build a lookup for gate tasks (used to recognize transitive cross-phase deps)
358		gateIDs := make(map[string]bool)
359		for _, t := range tasks {
360			if strings.HasSuffix(t.ID, task.IDSuffixGate) && t.Breaking {
361				gateIDs[t.ID] = true
362			}
363		}
364	
365		for key, t := range tasks {
366			if !task.IsBusinessTask(t.ID) {
367				continue
368			}
369			phase := task.GetTaskPhase(t.ID)
370			if phase <= 1 {
371				continue // Phase 1 has no previous phase
372			}
373			hasCrossPhaseDep := false
374			for _, dep := range t.Dependencies {
375				// Depending on a gate satisfies cross-phase ordering because gate N.gate
376				// (phase N) depends on N.summary, and the current task is in a later phase.
377				if gateIDs[dep] {
378					hasCrossPhaseDep = true
379					break
380				}
381				depPhase := task.GetTaskPhase(dep)
382				if depPhase > 0 && depPhase < phase {
383					hasCrossPhaseDep = true
384					break
385				}
386				// Check wildcard deps for cross-phase ordering
387				if strings.HasSuffix(dep, task.IDSuffixWildcard) {
388					if wp, err := strconv.Atoi(strings.TrimSuffix(dep, task.IDSuffixWildcard)); err == nil && wp < phase {
389						hasCrossPhaseDep = true
390						break
391					}
392				}
393			}
394			if !hasCrossPhaseDep {
395				v.warnings = append(v.warnings, fmt.Sprintf("Task '%s' (%s): no dependency on previous phase (may be claimed too early)", key, t.ID))
396			}
397		}
398	}
